window.ASBAB_NUZUL_CACHE["17"] = {"asbab_nuzul":{"57":[{"ar":"عَنْ عَبْدِ الله بْنِ مَسْعُودٍ رضي الله عنه { أُو۟لَـٰٓئِكَ ٱلَّذِينَ يَدْعُونَ يَبْتَغُونَ إِلَىٰ رَبِّهِمُ ٱلْوَسِيلَةَ } قَالَ: نَزَلَتْ فِي نَفَرٍ مِنْ الْعَرَبِ كَانُوا يَعْبُدُونَ نَفَرَاً مِنْ الْجِنِّ، فَأَسْلَمَ الْجِنِّيُّونَ، وَالْإِنْسُ الَّذِينَ كَانُوا يَعْبُدُونَهُمْ لَا يَشْعُرُونَ، فَنَزَلَتْ { أُو۟لَـٰٓئِكَ ٱلَّذِينَ يَدْعُونَ يَبْتَغُونَ إِلَىٰ رَبِّهِمُ ٱلْوَسِيلَةَ }. واللفظ لمسلم.","id":""}],"59":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: سَأَلَ أَهْلُ مَكَّةَ النَّبِيَّ ﷺ، أَنْ يَجْعَلَ لَهُمُ الصَّفَا ذَهَباً، وَأَنْ يُنَحِّيَ الْجِبَالَ عَنْهُمْ فَيَزْدَرِعُوا، فَقِيلَ لَهُ: إِنْ شِئْتَ أَنْ تَسْتَأْنِيَ بِهِمْ، وَإِنْ شِئْتَ أَنْ تُؤْتِيَهُمْ الَّذِي سَأَلُوا، فَإِنْ كَفَرُوا أُهْلِكُوا كَمَا أَهْلَكْتُ مَنْ قَبْلَهُمْ، قَالَ: « لَا بَلْ أَسْتَأْنِي بِهِمْ » فَأَنْزَلَ اللَّه عز و جل هَذِهِ الْآيَةَ { وَمَا مَنَعَنَآ أَن نُّرْسِلَ بِٱلْـَٔايَـٰتِ إِلَّآ أَن كَذَّبَ بِهَا ٱلْأَوَّلُونَ ۚ وَءَاتَيْنَا ثَمُودَ ٱلنَّاقَةَ مُبْصِرَةً }. واللفظ لأحمد.","id":""}],"80":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: كَانَ النَّبِيُّ ﷺ بِمَكَّةَ، ثُمَّ أُمِرَ بِالْهِجْرَةِ، فَنَزَلَتْ عَلَيْهِ: { وَقُل رَّبِّ أَدْخِلْنِى مُدْخَلَ صِدْقٍ وَأَخْرِجْنِى مُخْرَجَ صِدْقٍ وَٱجْعَل لِّى مِن لَّدُنكَ سُلْطَـٰنًا نَّصِيرًا ﴿٨٠﴾ }. واللفظ للترمذي.","id":""}],"85":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: قَالَتْ قُرَيْشٌ لِيَهُودَ: أَعْطُونَا شَيْئاً نَسْأَلُ هَذَا الرَّجُلَ، فَقَالَ: سَلُوهُ عَنِ الرُّوحِ، قَالَ: فَسَأَلُوهُ عَنِ الرُّوحِ، فَأَنْزَلَ اللهُ تَعَالَى { وَيَسْـَٔلُونَكَ عَنِ ٱلرُّوحِ ۖ قُلِ ٱلرُّوحُ مِنْ أَمْرِ رَبِّى وَمَآ أُوتِيتُم مِّنَ ٱلْعِلْمِ إِلَّا قَلِيلًا ﴿٨٥﴾ }، قَالُوا: أُوتِينَا عِلْماً كَثِيراً، أُوتِينَا التَّوْرَاةَ، وَمَنْ أُوتِيَ التَّوْرَاةَ فَقَدْ أُوتِيَ خَيْراً كَثِيراً، فَأُنْزِلَتْ: { قُل لَّوْ كَانَ ٱلْبَحْرُ مِدَادًا لِّكَلِمَـٰتِ رَبِّى لَنَفِدَ ٱلْبَحْرُ } إِلَى آخِرِ الآية. واللفظ للترمذي.","id":""}],"110":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما فِي قَوْلِهِ عز و جل: { وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا } قَالَ: نَزَلَتْ وَرَسُولُ اللهِ ﷺ مُتَوَارٍ بِمَكَّةَ، فَكَانَ إِذَا صَلَّى بِأَصْحَابِهِ رَفَعَ صَوْتَهُ بِالْقُرْآنِ، فَإِذَا سَمِعَ ذَلِكَ الْمُشْرِكُونَ سَبُّوا الْقُرْآنَ، وَمَنْ أَنْزَلَهُ، وَمَنْ جَاءَ بِهِ، فَقَالَ اللهُ تَعَالَى لِنَبِيِّهِ ﷺ: { وَلَا تَجْهَرْ بِصَلَاتِكَ } فَيَسْمَعَ الْمُشْرِكُونَ قِرَاءَتَكَ، { وَلَا تُخَافِتْ بِهَا } عَنْ أَصْحَابِكَ، أَسْمِعْهُمْ الْقُرْآنَ، وَلَا تَجْهَرُ ذَلِكَ الْجَهْرَ، { وَٱبْتَغِ بَيْنَ ذَٰلِكَ سَبِيلًا }، يَقُولُ: بَيْنَ الْجَهْرِ وَالْمُخَافَتَةِ. واللفظ لمسلم.","id":""},{"ar":"وللآية سبب ثان للنزول: فقد جاء عن ابن عباس رضي الله عنهما  قال: كان رسول الله ﷺ إذا جهر بالقرآن وهو يصلي، تفرقوا عنه وأبوا أن يسمعوا منه، فكان الرجل إذا أراد أن يسمع من رسول الله ﷺ بعض ما يتلو وهو يصلي، استرق السمع دونهم فرقاً منهم، فإذا رأى أنهم قد عرفوا أنه يستمع، ذهب خشية أذاهم فلم يسمع، فإن خفض صوته لم يسمع الذين يستمعون من قراءته شيئاً، فأنزل الله: { وَلَا تَجْهَرْ بِصَلَاتِكَ }، فيتفرقوا عنك، { وَلَا تُخَافِتْ بِهَا } فلا يسمع من أراد أن يسمع، ممن يسترق ذلك منهم، فلعله يرعوي إلى بعض ما يسمع فينتفع به، { وَٱبْتَغِ بَيْنَ ذَٰلِكَ سَبِيلًا }.","id":""}]},"mapping_ayat":{"17:1":[{"p":"Nasa'i","n":999,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مَنِيعٍ وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ قَالَا حَدَّثَنَا هُشَيْمٌ قَالَ حَدَّثَنَا أَبُو بِشْرٍ جَعْفَرُ بْنُ أَبِي وَحْشِيَّةَ وَهُوَ ابْنُ إِيَاسٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }قَالَ نَزَلَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُخْتَفٍ بِمَكَّةَ فَكَانَ إِذَا صَلَّى بِأَصْحَابِهِ رَفَعَ صَوْتَهُ وَقَالَ ابْنُ مَنِيعٍ يَجْهَرُ بِالْقُرْآنِ وَكَانَ الْمُشْرِكُونَ إِذَا سَمِعُوا صَوْتَهُ سَبُّوا الْقُرْآنَ وَمَنْ أَنْزَلَهُ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ عَزَّ وَجَلَّ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ }أَيْ بِقِرَاءَتِكَ فَيَسْمَعَ الْمُشْرِكُونَ فَيَسُبُّوا الْقُرْآنَ{ وَلَا تُخَافِتْ بِهَا }عَنْ أَصْحَابِكَ فَلَا يَسْمَعُوا{ وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }","trj":"Telah mengabarkan kepada kami [Ahmad bin Mani'] dan [Ya'qub bin Ibrahim Ad-Dauraqiy] mereka berdua berkata; telah menceritakan kepada kami [Husyaim] dia berkata; telah menceritakan kepada kami [Abu Bisyr Ja'far bin Abu Wahsyiyyah bin Iyas] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] tentang firman Allah Azza wa Jalla, \"Janganlah kamu mengeraskan suaramu dalam shalatmu dan Janganlah pula merendahkannya.\" (Qs. Al Israa' (17): 1 10), dia berkata; \"Ayat ini turun dan Rasulullah Shallallahu'alaihi wasallam masih sembunyi-sembunyi dalam berdakwah di Makkah. Jika beliau mengerjakan shalat dengan para sahabatnya, maka beliau Shallallahu'alaihi wasallam mengeraskan suaranya, Ibnu Mani' berkata, \"Beliau memperdengarkan bacaan Al Qur'annya. Adalah orang-orang musyrik yang mendengar suara Rasulullah Shallallahu'alaihi wasallam (saat membaca Al Qur'an) mencela Al Qur'an, yang menurunkannya (Allah), serta yang membawanya (malaikat Jibril). Oleh karena itu Allah Azza wa Jalla berfirman kepada nabi-Nya, \"Janganlah kamu mengeraskan suaramu dalam shalatmu\" yakni dalam bacaannya. -Jika- Orang musyrik mendengar hal ini, maka mereka mencela Al Qur'an.\"Dan janganlah pula melirihkannya\" dari sahabatmu hingga mereka tidak mendengar.\"Dan carilah jalannya diantara keadaan yang demikian.\" (Qs. Al Israa' (17): 110)."}],"17:10":[{"p":"Nasa'i","n":3509,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ قَالَ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ عَطَاءٍ وَهُوَ ابْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَقْرَبُوا مَالَ الْيَتِيمِ إِلَّا بِالَّتِي هِيَ أَحْسَنُ }وَ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ اجْتَنَبَ النَّاسُ مَالَ الْيَتِيمِ وَطَعَامَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَشَكَوْا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَيَسْأَلُونَكَ عَنْ الْيَتَامَى قُلْ إِصْلَاحٌ لَهُمْ خَيْرٌ إِلَى قَوْلِهِ لَأَعْنَتَكُمْ }","trj":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] berkata; telah menceritakan kepada kami [Muhammad bin Ash Shalt] berkata; telah menceritakan kepada kami [Abu Kudainah] dari ['Atha] -yaitu Ibnu As Saib- dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Tatkala turun ayat: '(Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat) ' (Qs. Al Israa': 34), serta '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ibnu Abbas berkata, \"Maka orang-orang menjauhi harta anak yatim dan makanannya, sehingga hal tersebut terasa berat atas orang-orang muslim. Maka mereka mengadukan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, kemudian Allah menurunkan ayat: '(Dan mereka bertanya kepadamu tentang anak yatim, katakalah: \"Mengurus urusan mereka secara patut adalah baik, dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu; dan Allah mengetahui siapa yang membuat kerusakan dari yang mengadakan perbaikan. Dan jikalau Allah menghendaki, niscaya Dia dapat mendatangkan kesulitan kepadamu) ' (Qs. Al Baqarah: 220)."}],"17:15":[{"p":"Abu Dawud","n":3775,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ إِيَادٍ حَدَّثَنَا إِيَادٌ عَنْ أَبِي رِمْثَةَ قَالَانْطَلَقْتُ مَعَ أَبِي نَحْوَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي ابْنُكَ هَذَا قَالَ إِي وَرَبِّ الْكَعْبَةِ قَالَ حَقًّا قَالَ أَشْهَدُ بِهِ قَالَ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَاحِكًا مِنْ ثَبْتِ شَبَهِي فِي أَبِي وَمِنْ حَلِفِ أَبِي عَلَيَّ ثُمَّ قَالَ أَمَا إِنَّهُ لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِ وَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }","trj":"Telah menceritakan kepada kami [Ahmad bin yunus] berkata, telah menceritakan kepada kami [Ubaidullah] -maksudnya Ubaidullah bin Iyad- berkata, telah menceritakan kepada kami [Iyad] dari [Abu Rimtsah] ia berkata; Aku dan bapakku berangkat menemui Nabi shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam bertanya kepada bapakku: \"Apakah ini anakmu?\" bapakku menjawab, \"Benar, demi Tuhannya Ka'bah.\" Beliau bertanya lagi: \"Apakah itu benar?\" bapakku menjawab, \"Aku bersaksi atasnya.\" Abu Rismtsah berkata, \"Rasulullah shallallahu 'alaihi wasallam lalu tersenyum karena aku mirip dengan bapakku dan karena sumpah yang dilakukannya atas diriku. Kemudian beliau bersabda: \"Ketahuilah, dia tidak akan memikul dosamu dan kamu tidak akan memikul dosanya.\" Lalu beliau membaca ayat: '(dan orang yang berdosa tidak akan memikul dosa orang lain) ' -Qs. Al Isra: 15-. "}],"17:33":[{"p":"Bukhari","n":3409,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ أَوْ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى قَالَ سَلْ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ مَا أَمْرُهُمَا{ وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ لَمَّا أُنْزِلَتْ الَّتِي فِي الْفُرْقَانِ قَالَ مُشْرِكُو أَهْلِ مَكَّةَ فَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَقَدْ أَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ }الْآيَةَ فَهَذِهِ لِأُولَئِكَ وَأَمَّا الَّتِي فِي النِّسَاءِ الرَّجُلُ إِذَا عَرَفَ الْإِسْلَامَ وَشَرَائِعَهُ ثُمَّ قَتَلَ فَجَزَاؤُهُ جَهَنَّمُفَذَكَرْتُهُ لِمُجَاهِدٍ فَقَالَإِلَّا مَنْ نَدِمَ","trj":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] telah menceritakan kepadaku [Sa'id bin Jubair] -atau dia berkata, telah menceritakan kepadaku [Al Hakam] dari [Sa'id bin Jubair] berkata, - 'Abdurrahman bin Abza menyuruhku, katanya; \"Tanyalah kepada Ibnu 'Abbas tentang dua ayat ini dan apa maksudnya, yaitu yang pertama firman Allah dalam QS al Isra` ayat 33; (\"Dan janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan haq (alasan yang benar) \" dan yang kedua firman Allah dalam QS an Nisaa' ayat 93: (\"Dan barangsiapa yang membunuh orang beriman dengan sengaja...\"). Maka aku bertanya kepada [Ibnu 'Abbas], maka dia menjelaskan; Ketika turun firman Allah yang serupa ini pada surah al Furqan, orang-orang musyrik penduduk Makkah berkata; \"Sungguh kita telah membunuh jiwa yang diharamkan Allah dan kita juga menyembah selain Allah dan kita telah banyak berbuat maksiat, maka Allah menurunkan firman-Nya yang artinya: \"...kecuali siapa yang bertaubat dan beriman...\" (QS al Furqan ayat 70). Nah, ayat-ayat ini turun untuk mereka. Adapun ayat yang ada dalam surah an Nisaa' adalah bila seseorang telah mengenal Islam dan syari'atnya, kemudian dia membunuh seseorang dengan sengaja maka balasan baginya adalah neraka jahannam\". Kemudian keterangan ini aku sampaikan kepada Mujahidmaka dia berkata; \"Kecuali siapa yang menyesali perbuartannya\"."}],"17:34":[{"p":"Nasa'i","n":3509,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ قَالَ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ عَطَاءٍ وَهُوَ ابْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَقْرَبُوا مَالَ الْيَتِيمِ إِلَّا بِالَّتِي هِيَ أَحْسَنُ }وَ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ اجْتَنَبَ النَّاسُ مَالَ الْيَتِيمِ وَطَعَامَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَشَكَوْا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَيَسْأَلُونَكَ عَنْ الْيَتَامَى قُلْ إِصْلَاحٌ لَهُمْ خَيْرٌ إِلَى قَوْلِهِ لَأَعْنَتَكُمْ }","trj":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] berkata; telah menceritakan kepada kami [Muhammad bin Ash Shalt] berkata; telah menceritakan kepada kami [Abu Kudainah] dari ['Atha] -yaitu Ibnu As Saib- dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Tatkala turun ayat: '(Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat) ' (Qs. Al Israa': 34), serta '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ibnu Abbas berkata, \"Maka orang-orang menjauhi harta anak yatim dan makanannya, sehingga hal tersebut terasa berat atas orang-orang muslim. Maka mereka mengadukan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, kemudian Allah menurunkan ayat: '(Dan mereka bertanya kepadamu tentang anak yatim, katakalah: \"Mengurus urusan mereka secara patut adalah baik, dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu; dan Allah mengetahui siapa yang membuat kerusakan dari yang mengadakan perbaikan. Dan jikalau Allah menghendaki, niscaya Dia dapat mendatangkan kesulitan kepadamu) ' (Qs. Al Baqarah: 220)."}],"17:40":[{"p":"Bukhari","n":6533,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقُلْنَا يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ قَالَ هَلْ تُضَارُونَ فِي رُؤْيَةِ الشَّمْسِ وَالْقَمَرِ إِذَا كَانَتْ صَحْوًا قُلْنَا لَا قَالَ فَإِنَّكُمْ لَا تُضَارُونَ فِي رُؤْيَةِ رَبِّكُمْ يَوْمَئِذٍ إِلَّا كَمَا تُضَارُونَ فِي رُؤْيَتِهِمَا ثُمَّ قَالَ يُنَادِي مُنَادٍ لِيَذْهَبْ كُلُّ قَوْمٍ إِلَى مَا كَانُوا يَعْبُدُونَ فَيَذْهَبُ أَصْحَابُ الصَّلِيبِ مَعَ صَلِيبِهِمْ وَأَصْحَابُ الْأَوْثَانِ مَعَ أَوْثَانِهِمْ وَأَصْحَابُ كُلِّ آلِهَةٍ مَعَ آلِهَتِهِمْ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ وَغُبَّرَاتٌ مِنْ أَهْلِ الْكِتَابِ ثُمَّ يُؤْتَى بِجَهَنَّمَ تُعْرَضُ كَأَنَّهَا سَرَابٌ فَيُقَالُ لِلْيَهُودِ مَا كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ عُزَيْرَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ قَالُوا نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ ثُمَّ يُقَالُ لِلنَّصَارَى مَا كُنْتُمْ تَعْبُدُونَ فَيَقُولُونَ كُنَّا نَعْبُدُ الْمَسِيحَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ فَيَقُولُونَ نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ فَيُقَالُ لَهُمْ مَا يَحْبِسُكُمْ وَقَدْ ذَهَبَ النَّاسُ فَيَقُولُونَ فَارَقْنَاهُمْ وَنَحْنُ أَحْوَجُ مِنَّا إِلَيْهِ الْيَوْمَ وَإِنَّا سَمِعْنَا مُنَادِيًا يُنَادِي لِيَلْحَقْ كُلُّ قَوْمٍ بِمَا كَانُوا يَعْبُدُونَ وَإِنَّمَا نَنْتَظِرُ رَبَّنَا قَالَ فَيَأْتِيهِمْ الْجَبَّارُ فِي صُورَةٍ غَيْرِ صُورَتِهِ الَّتِي رَأَوْهُ فِيهَا أَوَّلَ مَرَّةٍ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ أَنْتَ رَبُّنَا فَلَا يُكَلِّمُهُ إِلَّا الْأَنْبِيَاءُ فَيَقُولُ هَلْ بَيْنَكُمْ وَبَيْنَهُ آيَةٌ تَعْرِفُونَهُ فَيَقُولُونَ السَّاقُ فَيَكْشِفُ عَنْ سَاقِهِ فَيَسْجُدُ لَهُ كُلُّ مُؤْمِنٍ وَيَبْقَى مَنْ كَانَ يَسْجُدُ لِلَّهِ رِيَاءً وَسُمْعَةً فَيَذْهَبُ كَيْمَا يَسْجُدَ فَيَعُودُ ظَهْرُهُ طَبَقًا وَاحِدًا ثُمَّ يُؤْتَى بِالْجَسْرِ فَيُجْعَلُ بَيْنَ ظَهْرَيْ جَهَنَّمَ قُلْنَا يَا رَسُولَ اللَّهِ وَمَا الْجَسْرُ قَالَ مَدْحَضَةٌ مَزِلَّةٌ عَلَيْهِ خَطَاطِيفُ وَكَلَالِيبُ وَحَسَكَةٌ مُفَلْطَحَةٌ لَهَا شَوْكَةٌ عُقَيْفَاءُ تَكُونُ بِنَجْدٍ يُقَالُ لَهَا السَّعْدَانُ الْمُؤْمِنُ عَلَيْهَا كَالطَّرْفِ وَكَالْبَرْقِ وَكَالرِّيحِ وَكَأَجَاوِيدِ الْخَيْلِ وَالرِّكَابِ فَنَاجٍ مُسَلَّمٌ وَنَاجٍ مَخْدُوشٌ وَمَكْدُوسٌ فِي نَارِ جَهَنَّمَ حَتَّى يَمُرَّ آخِرُهُمْ يُسْحَبُ سَحْبًا فَمَا أَنْتُمْ بِأَشَدَّ لِي مُنَاشَدَةً فِي الْحَقِّ قَدْ تَبَيَّنَ لَكُمْ مِنْ الْمُؤْمِنِ يَوْمَئِذٍ لِلْجَبَّارِ وَإِذَا رَأَوْا أَنَّهُمْ قَدْ نَجَوْا فِي إِخْوَانِهِمْ يَقُولُونَ رَبَّنَا إِخْوَانُنَا كَانُوا يُصَلُّونَ مَعَنَا وَيَصُومُونَ مَعَنَا وَيَعْمَلُونَ مَعَنَا فَيَقُولُ اللَّهُ تَعَالَى اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ دِينَارٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ وَيُحَرِّمُ اللَّهُ صُوَرَهُمْ عَلَى النَّارِ فَيَأْتُونَهُمْ وَبَعْضُهُمْ قَدْ غَابَ فِي النَّارِ إِلَى قَدَمِهِ وَإِلَى أَنْصَافِ سَاقَيْهِ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ نِصْفِ دِينَارٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ ذَرَّةٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا قَالَ أَبُو سَعِيدٍ فَإِنْ لَمْ تُصَدِّقُونِي فَاقْرَءُوا{ إِنَّ اللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍ وَإِنْ تَكُ حَسَنَةً يُضَاعِفْهَا }فَيَشْفَعُ النَّبِيُّونَ وَالْمَلَائِكَةُ وَالْمُؤْمِنُونَ فَيَقُولُ الْجَبَّارُ بَقِيَتْ شَفَاعَتِي فَيَقْبِضُ قَبْضَةً مِنْ النَّارِ فَيُخْرِجُ أَقْوَامًا قَدْ امْتُحِشُوا فَيُلْقَوْنَ فِي نَهَرٍ بِأَفْوَاهِ الْجَنَّةِ يُقَالُ لَهُ مَاءُ الْحَيَاةِ فَيَنْبُتُونَ فِي حَافَتَيْهِ كَمَا تَنْبُتُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ قَدْ رَأَيْتُمُوهَا إِلَى جَانِبِ الصَّخْرَةِ وَإِلَى جَانِبِ الشَّجَرَةِ فَمَا كَانَ إِلَى الشَّمْسِ مِنْهَا كَانَ أَخْضَرَ وَمَا كَانَ مِنْهَا إِلَى الظِّلِّ كَانَ أَبْيَضَ فَيَخْرُجُونَ كَأَنَّهُمْ اللُّؤْلُؤُ فَيُجْعَلُ فِي رِقَابِهِمْ الْخَوَاتِيمُ فَيَدْخُلُونَ الْجَنَّةَ فَيَقُولُ أَهْلُ الْجَنَّةِ هَؤُلَاءِ عُتَقَاءُ الرَّحْمَنِ أَدْخَلَهُمْ الْجَنَّةَ بِغَيْرِ عَمَلٍ عَمِلُوهُ وَلَا خَيْرٍ قَدَّمُوهُ فَيُقَالُ لَهُمْ لَكُمْ مَا رَأَيْتُمْ وَمِثْلَهُ مَعَهُوَقَالَ حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُحْبَسُ الْمُؤْمِنُونَ يَوْمَ الْقِيَامَةِ حَتَّى يُهِمُّوا بِذَلِكَ فَيَقُولُونَ لَوْ اسْتَشْفَعْنَا إِلَى رَبِّنَا فَيُرِيحُنَا مِنْ مَكَانِنَا فَيَأْتُونَ آدَمَ فَيَقُولُونَ أَنْتَ آدَمُ أَبُو النَّاسِ خَلَقَكَ اللَّهُ بِيَدِهِ وَأَسْكَنَكَ جَنَّتَهُ وَأَسْجَدَ لَكَ مَلَائِكَتَهُ وَعَلَّمَكَ أَسْمَاءَ كُلِّ شَيْءٍ لِتَشْفَعْ لَنَا عِنْدَ رَبِّكَ حَتَّى يُرِيحَنَا مِنْ مَكَانِنَا هَذَا قَالَ فَيَقُولُ لَسْتُ هُنَاكُمْ قَالَ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ أَكْلَهُ مِنْ الشَّجَرَةِ وَقَدْ نُهِيَ عَنْهَا وَلَكِنْ ائْتُوا نُوحًا أَوَّلَ نَبِيٍّ بَعَثَهُ اللَّهُ إِلَى أَهْلِ الْأَرْضِ فَيَأْتُونَ نُوحًا فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ سُؤَالَهُ رَبَّهُ بِغَيْرِ عِلْمٍ وَلَكِنْ ائْتُوا إِبْرَاهِيمَ خَلِيلَ الرَّحْمَنِ قَالَ فَيَأْتُونَ إِبْرَاهِيمَ فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ ثَلَاث�� كَلِمَاتٍ كَذَبَهُنَّ وَلَكِنْ ائْتُوا مُوسَى عَبْدًا آتَاهُ اللَّهُ التَّوْرَاةَ وَكَلَّمَهُ وَقَرَّبَهُ نَجِيًّا قَالَ فَيَأْتُونَ مُوسَى فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ قَتْلَهُ النَّفْسَ وَلَكِنْ ائْتُوا عِيسَى عَبْدَ اللَّهِ وَرَسُولَهُ وَرُوحَ اللَّهِ وَكَلِمَتَهُ قَالَ فَيَأْتُونَ عِيسَى فَيَقُولُ لَسْتُ هُنَاكُمْ وَلَكِنْ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدًا غَفَرَ اللَّهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ فَيَأْتُونِي فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي فَيَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ أَيْضًا يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّانِيَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّالِثَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَهْ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَقَدْ سَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ حَتَّى مَا يَبْقَى فِي النَّارِ إِلَّا مَنْ حَبَسَهُ الْقُرْآنُ أَيْ وَجَبَ عَلَيْهِ الْخُلُودُ قَالَ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ عَسَى أَنْ يَبْعَثَكَ رَبُّكَ مَقَامًا مَحْمُودًا }قَالَ وَهَذَا الْمَقَامُ الْمَحْمُودُ الَّذِي وُعِدَهُ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Allaits bin Sa'd] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Zaid] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudzri] berkata, \"Kami bertanya, \"Ya Rasulullah, apakah kita akan melihat Tuhan kita pada hari kiamat?\" Nabi balik bertanya: \"Apakah kalian merasa kesulitan melihat matahari dan bulan ketika terang benderang?\" kami menjawab, \"Tidak.\" Nabi meneruskan: \"Begitulah kalian tidak kesulitan melihat melihat Tuhan kalian ketika itu, selain sebagaimana kesulitan kalian melihat keduanya.\" Kemudian beliau berkata: \"Lantas ada seorang penyeru memanggil-manggil, \"Hendaklah setiap kaum pergi menemui yang disembahnya!\" Maka pemuja salib pergi bersama salib mereka, dan pemuja patung menemui patung-patung mereka, dan setiap pemuja Tuhan bersama tuhan-tuhan mereka hingga tinggal orang-orang yang menyembah Allah, entah baik atau durhaka dan ahli kitab terdahulu. Kemudian jahannam didatangkan dan dipasang, ia seolah-olah fatamorgana, lantas orang-orang yahudi ditanya, \"Apa yang dahulu kalian sembah?\" Mereka menjawab, \"Kami dahulu menyembah Uzair anak Allah.\" Lalu ada suara, \"Kalian dusta! Allah sama sekali tidak mempunyai isteri dan tidak pula anak.\" Lalu apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin jika Engkau memberi kami minuman!\" Lantas ada suara, \"Minumlah kalian!\" Lalu mereka berjatuhan di neraka jahannam. Lantas orang-orang Nashara diseru, \"Apa yang kalian dahulu sembah?\" Mereka menjawab, \"Kami dahulu menyembah Isa al Masih, anak Anak Allah.\" Mereka dijawab, \"Kamu semua bohong! Allah sama sekali tidak mempunyai isteri atau bahkan anak, dan apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin agar Engkau memberi kami minuman!\" Lalu dijawab, \"Minumlah kalian!\" Dan langsung mereka berjatuhan di neraka jahannam hingga tersisa manusia yang menyembah Allah, entah yang baik atau berbuat durhaka. Mereka ditanya, \"Apa yang menyebabkan kalian tertahan padahal manusia lainnya sudah pergi?\" Mereka menjawab, \"Kami memisahkan diri dari mereka dan kami adalah manusia yang paling membutuhkan-Nya, kami dengar ada seorang juru seru menyerukan diri, \"Hendaklah setiap kaum menemui yang mereka sembah! Hanyasanya kami menunggu-nunggu Tuhan kami.\" Beliau melanjutkan, \"Lantas Allah (Al jabbar) mendatangi mereka dengan bentuk yang belum pernah mereka lihat pertama kali, lalu Allah firmankan: 'Akulah Tuhan kalian.' Mereka menjawab, 'Engkau adalah rabb kami, dan tidak ada yang berani mengajak-Nya bicara selain para nabi shallallahu 'alaihi wasallam, lantas para nabi berkata, 'Bukankah di antara kalian dan Allah ada tanda yang kalian mengenalnya? ' Mereka menjawab, 'Ya, yaitu betis, ' maka Allah pun menyingkap betis-Nya sehingga setiap mukmin bersujud kepada-Nya. Lalu tersisalah orang-orang yang sujud kepada Allah karena riya dan sum'ah sehingga ia pergi sujud dan punggungnya kembali menjadi satu bagian, kemudian titian (jembatan) jahannam didatangkan dan dipasang antara dua tepi jahannam, kami bertanya, 'Wahai Rasulullah, memang jembatan jahannam tersebut misterinya apa? ' Nabi menjawab: 'Jembatan itu bisa menggelincirkan, menjatuhkan, ada pengait-pengait besi, ada duri-duri yang lebar dan tajam, durinya besok yang terbuat dari kayu berduri namanya Sa'dan (kayu berduri tajam). Orang mukmin yang melewatinya sedemikian cepat, ada yang bagaikan kedipan mata, ada yang bagaikan kilat, ada yang bagaikan angin, dan ada yang bagaikan kuda pilihan. Ada yang bagaikan kuda tunggangan, ada yang selamat dengan betul-betul terselamatkan, namun ada juga yang selamat setelah tercabik-cabik oleh besi-besi pengait itu, atau terlempar karenanya di neraka jahannam, hingga manusia terakhir kali melewati dengan diseret seret, dan kalian tidak bisa sedemikian gigihnya menyumpahiku terhadap kebenaran yang jelas bagi kalian daripada terhadap seorang mukmin ketika itu kepada Allah Al Jabbar. Jika mereka melihat bahwasanya mereka telah selamat di kalangan teman-teman mereka, mereka berkata, 'Ya Tuhan kami, sesungguhnya kawan-kawan kami mendirikn shalat bersama kami dan berpuasa bersama kami, dan beramal bersama kami! ' Allah Ta'ala berfirman, 'Pergilah kalian, siapa diantara kalian dapatkan dalam hatinya masih ada seberat dinar keimanan, maka keluarkanlah dia', dan Allah mengharamkan bentuk mereka dalam neraka. Maka mereka datangi kawan-kawan mereka sedang sebagian mereka telah terendam dalam neraka ada yang sampai telapak kakinya, setengah betisnya, sehingga mereka keluarkan siapa saja yang mereka, kemudian mereka kembali dan Allah berkata, 'Pergilah kalian sekali lagi, dan siapa yang kalian temukan dalam hatinya seberat atom keimanan, maka keluarkanlah dia.' Maka mereka keluarkan siapa saja yang mereka kenal.\" Rasulullah berkata: 'Jika kalian tidak mempercayaiku, maka bacalah: '(Allah tidak menzhalimi seberat biji sawi pun, jika ada kebaikan, maka Allah melipatgandakan balasannya) ' (Qs. An nisaa': 40), maka para nabi shallallahu 'alaihi wasallam, malaikat dan orang-orang yang beriman, kesemuanya memberi syafaat. Kemudian Allah Al Jabbar berkata, syafaat-Ku masih ada. Lantas Allah menggenggam segenggam dari neraka dan mengentaskan beberapa kaum yang mereka telah terbakar, lantas mereka dilempar ke sebuah sungai di pintu surga yang namanya 'Sungai kehidupan' sehingga mereka tumbuh dalam kedua tepinya sebagaimana biji-bijian tumbuh dalam genangan sungai yang kalian sering melihatnya di samping batu karang dan samping pohon, apa yang diantaranya condong kepada matahari, maka berwarna hijau, dan apa yang diantaranya condong kepada bayangan, maka berwarna putih, lantas mereka muncul seolah-olah mutiara dan dalam tengkuk mereka terdapat cincin-cincin. Mereka kemudian masuk surga hingga penghuni surga berkata, 'Mereka adalah 'utaqa' Ar Rahman (orang-orang yang dibebaskan Arrahman), Allah memasukkan mereka bukan karena amal yang mereka lakukan, dan bukan pula karena kebaikan yang mereka persembahkan sehingga mereka memperoleh jawaban 'Bagimu yang kau lihat dan semisalnya'.\" [Hajjaj bin Minhal] berkata; telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dari [Anas] radliyallahu'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: 'Pada hari kiamat nanti orang-orang mukmin ditahan hingga yang demikian menjadikan mereka sedih. Mereka katakan, 'Duh, sekiranya kita meminta syafaat kepada Tuhan kami sehingga Dia menjadikan kita merasa nyaman dari tempat kita ini.' Mereka pun mendatangi Adam dan berkata, 'Engkau hai Adam, Engkau adalah nenek moyang seluruh manusia, Allah menciptamu dengan tangan-Nya, menjadikan surga sebagai tempat hunianmu dan menjadikan malaikat bertunduk sujud kepadamu, Allah juga mengajarimu nama-nama segala sesuatu agar engkau bisa memberi syafaat kepada kami disisi Tuhanmu sehingga engkau bisa memberi kenyamanan di tempat kami ini. Namun Adam hanya menjawab, 'Disini saya tak berhak memberi syafaat untuk kalian'.\" Rasulullah melanjutkan: \"Lantas Adam mengingatkan kesalahan yang pernah dilakukannya, yaitu memakan pohon larangan padahal telah dilarang, dan ia katakan 'Coba kalian datangi Nuh, sebab ia adalah nabi shallallahu 'alaihi wasallam pertama-tama yang Allah utus kepada penduduk bumi.' Mereka pun mendatangi Nuh, namun Nuh juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', dan Nuh menyebutkan kesalahan yang pernah dilakukannya, yaitu bertanya kepada Rabbnya dengan tanpa ilmu sambil ia katakan, 'Cobalah kalian datangi Ibrahim, sebab ia adalah Khalilurrahman (kekasih Arrahman).\" Rasulullah melanjutkan lagi kisahnya: \"Mereka pun mendatangi Ibrahim, hanya Ibrahim juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', Ibrahim lantas menyebutkan kesalahannya, yaitu tiga kebohongan yang pernah dilakukannya sambil berkata, 'Cobalah kalian datangi Musa, seorang hamba yang Allah memberinya taurat, mengajaknya bicara dan mendekatkannya kepada-Nya sedekat-dekatnya'.\" Rasulullah lanjutkan: \"Mereka pun mendatangi Musa, hanya Musa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil Musa mengingatkan kesalahan yang pernah dilakukannya, yaitu membunuh jiwa tanpa alasan yang dibenarkan, sambil ia katakan, 'Coba kalian datangi Isa, seorang hamba Allah dan rasul-Nya, ruh Allah dan kalimah-Nya. Merekapun mendatangi Isa, namun 'Isa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil ia katakan 'Cobalah kalian datangi Muhammad Shallallahu'alaihiwasallam, seorang hamba yang Allah telah mengampuni dosanya yang terdahulu dan yang akan datang.' Lantas mereka mendatangi aku (Muhammad) dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud, Allah lalu membiarkan aku sekehendak Dia membiarkaku. Allah lantas berkata, 'Angkat kepalamu hai Muhammad, katakanlah, engkau didengar, mintailah syafaat, engkau diberi syafaat, mintalah, engkau diberi.' Aku lalu angkat kepalaku dan aku memuji Tuhanku dengan pujian yang Ia ajarkannya kepadaku, kemudian aku memberi syafaat dan Dia memberiku batasan. Kemudian aku keluar dan memasukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku juga mendengarnya menyebutkan, \"Aku lalu keluar, kemudian aku keluarkan mereka dari neraka dan kumasukkan ke dalam surga. Setelah itu aku kembali untuk kali kedua dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan untuk menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud. Allah lantas membiarkanku sekehendak Allah membiarkan, kemudian Allah berkata, 'Angkatlah kepalamu hai Muhammad dan katakanlah engkau akan didengar, dan berilah syafaat engkau akan diberi syafaat, dan mintalah engkau akan diberi.' Aku lalu angkat kepalaku dan memanjatkan pujian dan pujaan terhadap tuhanku sebagaimana yang diajakrkan-Nya kepadaku. Kemudian aku memberi syafaat, dan Ia memberiku batasan sehingga aku keluar dan aku masukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, \"Dan aku berangkat sehingga aku keluarkan mereka dari neraka, lalu mereka aku masukkan ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, 'Maka aku berangkat dan aku keluarkan mereka dari neraka, untuk kemudian aku masukkan mereka ke dalam surga, hingga tidak tersisa dalam neraka selain yang digi ditahan oleh alquran, atau maksudnya ia wajib abadi, kemudian beliau membaca ayat ini '(semoga Tuhanmu membangkitkankmu di tempat yang terpuji) ' (Qs. Al Isra': 79). Nabi mengatakan, \"Inilah maqam terpuji yang dijanjikan untuk nabi shallallahu 'alaihi wasallam kalian.\""}],"17:49":[{"p":"Bukhari","n":3675,"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ يَوْمَ الْفَتْحِ وَحَوْلَ الْبَيْتِ سِتُّونَ وَثَلَاثُ مِائَةِ نُصُبٍ فَجَعَلَ يَطْعُنُهَا بِعُودٍ فِي يَدِهِ وَيَقُولُ{ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ }{ جَاءَ الْحَقُّ وَمَا يُبْدِئُ الْبَاطِلُ وَمَا يُعِيدُ }","trj":"Telah menceritakan kepada kami [Shadaqah bin Fadhl] Telah mengabarkan kepada kami [Ibnu 'Uyainah] dari [Ibnu Abu Najih] dari [Mujahid] dari [Abu Ma'mar] dari [Abdullah] radliallahu 'anhu, katanya, Nabi shallallahu 'alaihi wasallam memasuki Makkah pada penaklukan Makkah yang ketika itu di sekitar ka'bah ada tiga ratus enam puluh patung, lantas beliau porak-porandakan dengan sebongkah kayu di tangannya seraya beliau serukan \"Sekarang telah datang kebenaran dan kebatilan telah musnah.\" (QS. Isra'; 81), \"Sekarang kebenaran telah datang dan kebatilan tak akan terulang dan kembali lagi.\" (QS. Saba': 49)."},{"p":"Muslim","n":3100,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ وَابْنُ أَبِي عُمَرَ وَاللَّفْظُ لِابْنِ أَبِي شَيْبَةَ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَحَوْلَ الْكَعْبَةِ ثَلَاثُ مِائَةٍ وَسِتُّونَ نُصُبًا فَجَعَلَ يَطْعُنُهَا بِعُودٍ كَانَ بِيَدِهِ وَيَقُولُ{ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ إِنَّ الْبَاطِلَ كَانَ زَهُوقًا }{ جَاءَ الْحَقُّ وَمَا يُبْدِئُ الْبَاطِلُ وَمَا يُعِيدُ }زَادَ ابْنُ أَبِي عُمَرَ يَوْمَ الْفَتْحِو حَدَّثَنَاه حَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ كِلَاهُمَا عَنْ عَبْدِ الرَّزَّاقِ أَخْبَرَنَا الثَّوْرِيُّ عَنْ ابْنِ أَبِي نَجِيحٍ بِهَذَا الْإِسْنَادِ إِلَى قَوْلِهِ زَهُوقًا وَلَمْ يَذْكُرْ الْآيَةَ الْأُخْرَى وَقَالَ بَدَلَ نُصُبًا صَنَمًا","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan ['Amru An Naqid] serta [Ibnu Abu Umar] sedangkan lafadznya dari Ibnu Abu Syaibah, mereka berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ibnu Abu Najih] dari [Mujahid] dari [Abu Ma'mar] dari [Abdullah] dia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam masuk Makkah, saat itu terdapat tiga ratus enam puluh patung di sekitar Ka'bah. Lantas dengan tongkatnya beliau memukul patung tersebut sambil membaca: \"Telah datang kebenaran dan lenyaplah kebatilan, sesungguhnya kebatilan pasti lenyap…) ' (Qs. Al Israa: 81) '(Kebenaran telah datang dan yang batil itu tidak akan memulai dan tidak (pula) akan mengulangi) ' (Qs. Sabaa: 49). Ibnu Abu Umar menambahkan, \"Ketika hari penaklukan Kota Makkah.\" Dan telah menceritakan kepada kami [Hasan bin Ali Al Khulwani] dan [Abd bin Humaid] keduanya dari [Abdurrazaq] telah mengabarkan kepada kami [At Tsauri] dari [Ibnu Abu Najih] dengan isnad ini hingga perkataan, \"(dan kebatilan) itu pasti lenyap.\" Dan tidak menyebutkan ayat yang lain, dia juga berkata, \"Arca\" sebagai ganti dari \"Patung.\""}],"17:51":[{"p":"Bukhari","n":4034,"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ قَالَ سَمِعْتُ ابْنَ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُقَالَ فِي بَنِي إِسْرَائِيلَ وَالْكَهْفِ وَمَرْيَمَ إِنَّهُنَّ مِنْ الْعِتَاقِ الْأُوَلِ وَهُنَّ مِنْ تِلَادِي{ فَسَيُنْغِضُونَ إِلَيْكَ رُءُوسَهُمْ }قَالَ ابْنُ عَبَّاسٍ يَهُزُّونَ وَقَالَ غَيْرُهُ نَغَضَتْ سِنُّكَ أَيْ تَحَرَّكَتْ","trj":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; Aku mendengar ['Abdur Rahman bin Yazid] dia berkata; Aku mendengar [Ibnu Mas'ud radliallahu 'anhu] dia berkata mengenai surat Bani Israil, Ashabul Al Kahfi, dan Maryam; Mereka adalah orang-orang terdahulu, dan surat-surat itu sudah lama aku membacanya. Adapun arti Lalu mereka akan menggeleng-gelengkan kepala mereka.. (Al Israa: 51). Ibnu Abbas berkata; yaitu menggerak-gerakannya. Yang lainnya berkata; 'Naghdlat Sinnuka.' Yakni; gigimu bergerak-gerak."}],"17:60":[{"p":"Bukhari","n":3442,"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَافِي قَوْلِهِ تَعَالَى{ وَمَا جَعَلْنَا الرُّؤْيَا الَّتِي أَرَيْنَاكَ إِلَّا فِتْنَةً لِلنَّاسِ }قَالَ هِيَ رُؤْيَا عَيْنٍ أُرِيَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ إِلَى بَيْتِ الْمَقْدِسِ قَالَ{ وَالشَّجَرَةَ الْمَلْعُونَةَ فِي الْقُرْآنِ }قَالَ هِيَ شَجَرَةُ الزَّقُّومِ","trj":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru] dari ['Ikrimah] dari [Ibnu 'Abbas] radliallahu 'anhuma tentang firman Allah Ta'ala QS al Isra' ayat 60: (\"Dan tidaklah kami jdikan mimpi yang Kami perlihatkann kepadamu melainkan sebagai ujian bagi manusia\"). Ibnu 'Abbas radliallahu 'anhuma berkata; \"Itu adalah penglihatan mata telanjang yang diperlihatkan kepada Rasulullah shallallahu 'alaihi wasallam pada malam beliau di Isra' menuju Baitul Maqdis\". Dan Ibnu 'Abbas radliallahu 'anhuma juga berkata; bahwa lanjutan ayat yang artinya: (\"dan begitu pula pohon yang terkutuk di dalam al Qur'an.\".) maksudnya adalah pohon zaqqum (di neraka) \"."},{"p":"Tirmidzi","n":2909,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ وَمَا جَعَلْنَا الرُّؤْيَا الَّتِي أَرَيْنَاكَ إِلَّا فِتْنَةً لِلنَّاسِ }قَالَ هِيَ رُؤْيَا عَيْنٍ أُرِيَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ إِلَى بَيْتِ الْمَقْدِسِ قَالَ{ وَالشَّجَرَةَ الْمَلْعُونَةَ فِي الْقُرْآنِ }هِيَ شَجَرَةُ الزَّقُّومِقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Amru bin Dinar] dari [Ikrimah] dari [Ibnu Abbas] berkenaan dengan firman: \"Dan Kami tidak menjadikan mimpi yang telah Kami perlihatkan kepadamu, melainkan sebagai ujian bagi manusia\" (QS. Al-Isra'; 60), itulah mimpi nyata yang diperlihatkan kepada nabi Shallallahu 'alaihi wa Salam saat diisra`kan ke Baitul Maqdis, \"Dan (begitu pula) pohon kayu yang terkutuk dalam Al Qur`an.\" (Al Israa`: 60) maksudnya adalah pohon Zaqqum.\" Abu Isa mengatakan bahwa hadits ini hasan shahih."}],"17:70":[{"p":"Bukhari","n":3409,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ أَوْ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى قَالَ سَلْ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ مَا أَمْرُهُمَا{ وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ لَمَّا أُنْزِلَتْ الَّتِي فِي الْفُرْقَانِ قَالَ مُشْرِكُو أَهْلِ مَكَّةَ فَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَقَدْ أَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ }الْآيَةَ فَهَذِهِ لِأُولَئِكَ وَأَمَّا الَّتِي فِي النِّسَاءِ الرَّجُلُ إِذَا عَرَفَ الْإِسْلَامَ وَشَرَائِعَهُ ثُمَّ قَتَلَ فَجَزَاؤُهُ جَهَنَّمُفَذَكَرْتُهُ لِمُجَاهِدٍ فَقَالَإِلَّا مَنْ نَدِمَ","trj":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] telah menceritakan kepadaku [Sa'id bin Jubair] -atau dia berkata, telah menceritakan kepadaku [Al Hakam] dari [Sa'id bin Jubair] berkata, - 'Abdurrahman bin Abza menyuruhku, katanya; \"Tanyalah kepada Ibnu 'Abbas tentang dua ayat ini dan apa maksudnya, yaitu yang pertama firman Allah dalam QS al Isra` ayat 33; (\"Dan janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan haq (alasan yang benar) \" dan yang kedua firman Allah dalam QS an Nisaa' ayat 93: (\"Dan barangsiapa yang membunuh orang beriman dengan sengaja...\"). Maka aku bertanya kepada [Ibnu 'Abbas], maka dia menjelaskan; Ketika turun firman Allah yang serupa ini pada surah al Furqan, orang-orang musyrik penduduk Makkah berkata; \"Sungguh kita telah membunuh jiwa yang diharamkan Allah dan kita juga menyembah selain Allah dan kita telah banyak berbuat maksiat, maka Allah menurunkan firman-Nya yang artinya: \"...kecuali siapa yang bertaubat dan beriman...\" (QS al Furqan ayat 70). Nah, ayat-ayat ini turun untuk mereka. Adapun ayat yang ada dalam surah an Nisaa' adalah bila seseorang telah mengenal Islam dan syari'atnya, kemudian dia membunuh seseorang dengan sengaja maka balasan baginya adalah neraka jahannam\". Kemudian keterangan ini aku sampaikan kepada Mujahidmaka dia berkata; \"Kecuali siapa yang menyesali perbuartannya\"."}],"17:78":[{"p":"Bukhari","n":612,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَفْضُلُ صَلَاةُ الْجَمِيعِ صَلَاةَ أَحَدِكُمْ وَحْدَهُ بِخَمْسٍ وَعِشْرِينَ جُزْءًا وَتَجْتَمِعُ مَلَائِكَةُ اللَّيْلِ وَمَلَائِكَةُ النَّهَارِ فِي صَلَاةِ الْفَجْرِ ثُمَّ يَقُولُ أَبُو هُرَيْرَةَ فَاقْرَءُوا إِنْ شِئْتُمْ{ إِنَّ قُرْآنَ الْفَجْرِ كَانَ مَشْهُودًا }قَالَ شُعَيْبٌ وَحَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ تَفْضُلُهَا بِسَبْعٍ وَعِشْرِينَ دَرَجَةً","trj":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdurrahman] bahwa [Abu Hurairah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat berjama'ah lebih utama dibanding shalatnya salah seorang dari kalian dengan sendirian dengan dua puluh lima bagian. Dan Malaikat malam dan Malaikat siang berkumpul pada shalat fajar.\" Abu Hurairah kemudian berkata, \"Jika mau silahkan baca: '(Sesungguhnya shalat fajar disaksikan (oleh para Malaikat) ' (Qs. Al Israa: 78). [Syu'aib] berkata; telah menceritakan kepadaku [Nafi'] dari ['Abdullah bin 'Umar] ia berkata, \"(Shalat berjama'ah) dilebihkan dengan dua puluh tujuh derajat.\""}],"17:79":[{"p":"Bukhari","n":6533,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقُلْنَا يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ قَالَ هَلْ تُضَارُونَ فِي رُؤْيَةِ الشَّمْسِ وَالْقَمَرِ إِذَا كَانَتْ صَحْوًا قُلْنَا لَا قَالَ فَإِنَّكُمْ لَا تُضَارُونَ فِي رُؤْيَةِ رَبِّكُمْ يَوْمَئِذٍ إِلَّا كَمَا تُضَارُونَ فِي رُؤْيَتِهِمَا ثُمَّ قَالَ يُنَادِي مُنَادٍ لِيَذْهَبْ كُلُّ قَوْمٍ إِلَى مَا كَانُوا يَعْبُدُونَ فَيَذْهَبُ أَصْحَابُ الصَّلِيبِ مَعَ صَلِيبِهِمْ وَأَصْحَابُ الْأَوْثَانِ مَعَ أَوْثَانِهِمْ وَأَصْحَابُ كُلِّ آلِهَةٍ مَعَ آلِهَتِهِمْ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ وَغُبَّرَاتٌ مِنْ أَهْلِ الْكِتَابِ ثُمَّ يُؤْتَى بِجَهَنَّمَ تُعْرَضُ كَأَنَّهَا سَرَابٌ فَيُقَالُ لِلْيَهُودِ مَا كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ عُزَيْرَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ قَالُوا نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ ثُمَّ يُقَالُ لِلنَّصَارَى مَا كُنْتُمْ تَعْبُدُونَ فَيَقُولُونَ كُنَّا نَعْبُدُ الْمَسِيحَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ فَيَقُولُونَ نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ فَيُقَالُ لَهُمْ مَا يَحْبِسُكُمْ وَقَدْ ذَهَبَ النَّاسُ فَيَقُولُونَ فَارَقْنَاهُمْ وَنَحْنُ أَحْوَجُ مِنَّا إِلَيْهِ الْيَوْمَ وَإِنَّا سَمِعْنَا مُنَادِيًا يُنَادِي لِيَلْحَقْ كُلُّ قَوْمٍ بِمَا كَانُوا يَعْبُدُونَ وَإِنَّمَا نَنْتَظِرُ رَبَّنَا قَالَ فَيَأْتِيهِمْ الْجَبَّارُ فِي صُورَةٍ غَيْرِ صُورَتِهِ الَّتِي رَأَوْهُ فِيهَا أَوَّلَ مَرَّةٍ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ أَنْتَ رَبُّنَا فَلَا يُكَلِّمُهُ إِلَّا الْأَنْبِيَاءُ فَيَقُولُ هَلْ بَيْنَكُمْ وَبَيْنَهُ آيَةٌ تَعْرِفُونَهُ فَيَقُولُونَ السَّاقُ فَيَكْشِفُ عَنْ سَاقِهِ فَيَسْجُدُ لَهُ كُلُّ مُؤْمِنٍ وَيَبْقَى مَنْ كَانَ يَسْجُدُ لِلَّهِ رِيَاءً وَسُمْعَةً فَيَذْهَبُ كَيْمَا يَسْجُدَ فَيَعُودُ ظَهْرُهُ طَبَقًا وَاحِدًا ثُمَّ يُؤْتَى بِالْجَسْرِ فَيُجْعَلُ بَيْنَ ظَهْرَيْ جَهَنَّمَ قُلْنَا يَا رَسُولَ اللَّهِ وَمَا الْجَسْرُ قَالَ مَدْحَضَةٌ مَزِلَّةٌ عَلَيْهِ خَطَاطِيفُ وَكَلَالِيبُ وَحَسَكَةٌ مُفَلْطَحَةٌ لَهَا شَوْكَةٌ عُقَيْفَاءُ تَكُونُ بِنَجْدٍ يُقَالُ لَهَا السَّعْدَانُ الْمُؤْمِنُ عَلَيْهَا كَالطَّرْفِ وَكَالْبَرْقِ وَكَالرِّيحِ وَكَأَجَاوِيدِ الْخَيْلِ وَالرِّكَابِ فَنَاجٍ مُسَلَّمٌ وَنَاجٍ مَخْدُوشٌ وَمَكْدُوسٌ فِي نَارِ جَهَنَّمَ حَتَّى يَمُرَّ آخِرُهُمْ يُسْحَبُ سَحْبًا فَمَا أَنْتُمْ بِأَشَدَّ لِي مُنَاشَدَةً فِي الْحَقِّ قَدْ تَبَيَّنَ لَكُمْ مِنْ الْمُؤْمِنِ يَوْمَئِذٍ لِلْجَبَّارِ وَإِذَا رَأَوْا أَنَّهُمْ قَدْ نَجَوْا فِي إِخْوَانِهِمْ يَقُولُونَ رَبَّنَا إِخْوَانُنَا كَانُوا يُصَلُّونَ مَعَنَا وَيَصُومُونَ مَعَنَا وَيَعْمَلُونَ مَعَنَا فَيَقُولُ اللَّهُ تَعَالَى اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ دِينَارٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ وَيُحَرِّمُ اللَّهُ صُوَرَهُمْ عَلَى النَّارِ فَيَأْتُونَهُمْ وَبَعْضُهُمْ قَدْ غَابَ فِي النَّارِ إِلَى قَدَمِهِ وَإِلَى أَنْصَافِ سَاقَيْهِ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ نِصْفِ دِينَارٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ ذَرَّةٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا قَالَ أَبُو سَعِيدٍ فَإِنْ لَمْ تُصَدِّقُونِي فَاقْرَءُوا{ إِنَّ اللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍ وَإِنْ تَكُ حَسَنَةً يُضَاعِفْهَا }فَيَشْفَعُ النَّبِيُّونَ وَالْمَلَائِكَةُ وَالْمُؤْمِنُونَ فَيَقُولُ الْجَبَّارُ بَقِيَتْ شَفَاعَتِي فَيَقْبِضُ قَبْضَةً مِنْ النَّارِ فَيُخْرِجُ أَقْوَامًا قَدْ امْتُحِشُوا فَيُلْقَوْنَ فِي نَهَرٍ بِأَفْوَاهِ الْجَنَّةِ يُقَالُ لَهُ مَاءُ الْحَيَاةِ فَيَنْبُتُونَ فِي حَافَتَيْهِ كَمَا تَنْبُتُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ قَدْ رَأَيْتُمُوهَا إِلَى جَانِبِ الصَّخْرَةِ وَإِلَى جَانِبِ الشَّجَرَةِ فَمَا كَانَ إِلَى الشَّمْسِ مِنْهَا كَانَ أَخْضَرَ وَمَا كَانَ مِنْهَا إِلَى الظِّلِّ كَانَ أَبْيَضَ فَيَخْرُجُونَ كَأَنَّهُمْ اللُّؤْلُؤُ فَيُجْعَلُ فِي رِقَابِهِمْ الْخَوَاتِيمُ فَيَدْخُلُونَ الْجَنَّةَ فَيَقُولُ أَهْلُ الْجَنَّةِ هَؤُلَاءِ عُتَقَاءُ الرَّحْمَنِ أَدْخَلَهُمْ الْجَنَّةَ بِغَيْرِ عَمَلٍ عَمِلُوهُ وَلَا خَيْرٍ قَدَّمُوهُ فَيُقَالُ لَهُمْ لَكُمْ مَا رَأَيْتُمْ وَمِثْلَهُ مَعَهُوَقَالَ حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُحْبَسُ الْمُؤْمِنُونَ يَوْمَ الْقِيَامَةِ حَتَّى يُهِمُّوا بِذَلِكَ فَيَقُولُونَ لَوْ اسْتَشْفَعْنَا إِلَى رَبِّنَا فَيُرِيحُنَا مِنْ مَكَانِنَا فَيَأْتُونَ آدَمَ فَيَقُولُونَ أَنْتَ آدَمُ أَبُو النَّاسِ خَلَقَكَ اللَّهُ بِيَدِهِ وَأَسْكَنَكَ جَنَّتَهُ وَأَسْجَدَ لَكَ مَلَائِكَتَهُ وَعَلَّمَكَ أَسْمَاءَ كُلِّ شَيْءٍ لِتَشْفَعْ لَنَا عِنْدَ رَبِّكَ حَتَّى يُرِيحَنَا مِنْ مَكَانِنَا هَذَا قَالَ فَيَقُولُ لَسْتُ هُنَاكُمْ قَالَ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ أَكْلَهُ مِنْ الشَّجَرَةِ وَقَدْ نُهِيَ عَنْهَا وَلَكِنْ ائْتُوا نُوحًا أَوَّلَ نَبِيٍّ بَعَثَهُ اللَّهُ إِلَى أَهْلِ الْأَرْضِ فَيَأْتُونَ نُوحًا فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ سُؤَالَهُ رَبَّهُ بِغَيْرِ عِلْمٍ وَلَكِنْ ائْتُوا إِبْرَاهِيمَ خَلِيلَ الرَّحْمَنِ قَالَ فَيَأْتُونَ إِبْرَاهِيمَ فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ ثَلَاث�� كَلِمَاتٍ كَذَبَهُنَّ وَلَكِنْ ائْتُوا مُوسَى عَبْدًا آتَاهُ اللَّهُ التَّوْرَاةَ وَكَلَّمَهُ وَقَرَّبَهُ نَجِيًّا قَالَ فَيَأْتُونَ مُوسَى فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ قَتْلَهُ النَّفْسَ وَلَكِنْ ائْتُوا عِيسَى عَبْدَ اللَّهِ وَرَسُولَهُ وَرُوحَ اللَّهِ وَكَلِمَتَهُ قَالَ فَيَأْتُونَ عِيسَى فَيَقُولُ لَسْتُ هُنَاكُمْ وَلَكِنْ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدًا غَفَرَ اللَّهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ فَيَأْتُونِي فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي فَيَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ أَيْضًا يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّانِيَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّالِثَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَهْ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَقَدْ سَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ حَتَّى مَا يَبْقَى فِي النَّارِ إِلَّا مَنْ حَبَسَهُ الْقُرْآنُ أَيْ وَجَبَ عَلَيْهِ الْخُلُودُ قَالَ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ عَسَى أَنْ يَبْعَثَكَ رَبُّكَ مَقَامًا مَحْمُودًا }قَالَ وَهَذَا الْمَقَامُ الْمَحْمُودُ الَّذِي وُعِدَهُ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Allaits bin Sa'd] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Zaid] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudzri] berkata, \"Kami bertanya, \"Ya Rasulullah, apakah kita akan melihat Tuhan kita pada hari kiamat?\" Nabi balik bertanya: \"Apakah kalian merasa kesulitan melihat matahari dan bulan ketika terang benderang?\" kami menjawab, \"Tidak.\" Nabi meneruskan: \"Begitulah kalian tidak kesulitan melihat melihat Tuhan kalian ketika itu, selain sebagaimana kesulitan kalian melihat keduanya.\" Kemudian beliau berkata: \"Lantas ada seorang penyeru memanggil-manggil, \"Hendaklah setiap kaum pergi menemui yang disembahnya!\" Maka pemuja salib pergi bersama salib mereka, dan pemuja patung menemui patung-patung mereka, dan setiap pemuja Tuhan bersama tuhan-tuhan mereka hingga tinggal orang-orang yang menyembah Allah, entah baik atau durhaka dan ahli kitab terdahulu. Kemudian jahannam didatangkan dan dipasang, ia seolah-olah fatamorgana, lantas orang-orang yahudi ditanya, \"Apa yang dahulu kalian sembah?\" Mereka menjawab, \"Kami dahulu menyembah Uzair anak Allah.\" Lalu ada suara, \"Kalian dusta! Allah sama sekali tidak mempunyai isteri dan tidak pula anak.\" Lalu apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin jika Engkau memberi kami minuman!\" Lantas ada suara, \"Minumlah kalian!\" Lalu mereka berjatuhan di neraka jahannam. Lantas orang-orang Nashara diseru, \"Apa yang kalian dahulu sembah?\" Mereka menjawab, \"Kami dahulu menyembah Isa al Masih, anak Anak Allah.\" Mereka dijawab, \"Kamu semua bohong! Allah sama sekali tidak mempunyai isteri atau bahkan anak, dan apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin agar Engkau memberi kami minuman!\" Lalu dijawab, \"Minumlah kalian!\" Dan langsung mereka berjatuhan di neraka jahannam hingga tersisa manusia yang menyembah Allah, entah yang baik atau berbuat durhaka. Mereka ditanya, \"Apa yang menyebabkan kalian tertahan padahal manusia lainnya sudah pergi?\" Mereka menjawab, \"Kami memisahkan diri dari mereka dan kami adalah manusia yang paling membutuhkan-Nya, kami dengar ada seorang juru seru menyerukan diri, \"Hendaklah setiap kaum menemui yang mereka sembah! Hanyasanya kami menunggu-nunggu Tuhan kami.\" Beliau melanjutkan, \"Lantas Allah (Al jabbar) mendatangi mereka dengan bentuk yang belum pernah mereka lihat pertama kali, lalu Allah firmankan: 'Akulah Tuhan kalian.' Mereka menjawab, 'Engkau adalah rabb kami, dan tidak ada yang berani mengajak-Nya bicara selain para nabi shallallahu 'alaihi wasallam, lantas para nabi berkata, 'Bukankah di antara kalian dan Allah ada tanda yang kalian mengenalnya? ' Mereka menjawab, 'Ya, yaitu betis, ' maka Allah pun menyingkap betis-Nya sehingga setiap mukmin bersujud kepada-Nya. Lalu tersisalah orang-orang yang sujud kepada Allah karena riya dan sum'ah sehingga ia pergi sujud dan punggungnya kembali menjadi satu bagian, kemudian titian (jembatan) jahannam didatangkan dan dipasang antara dua tepi jahannam, kami bertanya, 'Wahai Rasulullah, memang jembatan jahannam tersebut misterinya apa? ' Nabi menjawab: 'Jembatan itu bisa menggelincirkan, menjatuhkan, ada pengait-pengait besi, ada duri-duri yang lebar dan tajam, durinya besok yang terbuat dari kayu berduri namanya Sa'dan (kayu berduri tajam). Orang mukmin yang melewatinya sedemikian cepat, ada yang bagaikan kedipan mata, ada yang bagaikan kilat, ada yang bagaikan angin, dan ada yang bagaikan kuda pilihan. Ada yang bagaikan kuda tunggangan, ada yang selamat dengan betul-betul terselamatkan, namun ada juga yang selamat setelah tercabik-cabik oleh besi-besi pengait itu, atau terlempar karenanya di neraka jahannam, hingga manusia terakhir kali melewati dengan diseret seret, dan kalian tidak bisa sedemikian gigihnya menyumpahiku terhadap kebenaran yang jelas bagi kalian daripada terhadap seorang mukmin ketika itu kepada Allah Al Jabbar. Jika mereka melihat bahwasanya mereka telah selamat di kalangan teman-teman mereka, mereka berkata, 'Ya Tuhan kami, sesungguhnya kawan-kawan kami mendirikn shalat bersama kami dan berpuasa bersama kami, dan beramal bersama kami! ' Allah Ta'ala berfirman, 'Pergilah kalian, siapa diantara kalian dapatkan dalam hatinya masih ada seberat dinar keimanan, maka keluarkanlah dia', dan Allah mengharamkan bentuk mereka dalam neraka. Maka mereka datangi kawan-kawan mereka sedang sebagian mereka telah terendam dalam neraka ada yang sampai telapak kakinya, setengah betisnya, sehingga mereka keluarkan siapa saja yang mereka, kemudian mereka kembali dan Allah berkata, 'Pergilah kalian sekali lagi, dan siapa yang kalian temukan dalam hatinya seberat atom keimanan, maka keluarkanlah dia.' Maka mereka keluarkan siapa saja yang mereka kenal.\" Rasulullah berkata: 'Jika kalian tidak mempercayaiku, maka bacalah: '(Allah tidak menzhalimi seberat biji sawi pun, jika ada kebaikan, maka Allah melipatgandakan balasannya) ' (Qs. An nisaa': 40), maka para nabi shallallahu 'alaihi wasallam, malaikat dan orang-orang yang beriman, kesemuanya memberi syafaat. Kemudian Allah Al Jabbar berkata, syafaat-Ku masih ada. Lantas Allah menggenggam segenggam dari neraka dan mengentaskan beberapa kaum yang mereka telah terbakar, lantas mereka dilempar ke sebuah sungai di pintu surga yang namanya 'Sungai kehidupan' sehingga mereka tumbuh dalam kedua tepinya sebagaimana biji-bijian tumbuh dalam genangan sungai yang kalian sering melihatnya di samping batu karang dan samping pohon, apa yang diantaranya condong kepada matahari, maka berwarna hijau, dan apa yang diantaranya condong kepada bayangan, maka berwarna putih, lantas mereka muncul seolah-olah mutiara dan dalam tengkuk mereka terdapat cincin-cincin. Mereka kemudian masuk surga hingga penghuni surga berkata, 'Mereka adalah 'utaqa' Ar Rahman (orang-orang yang dibebaskan Arrahman), Allah memasukkan mereka bukan karena amal yang mereka lakukan, dan bukan pula karena kebaikan yang mereka persembahkan sehingga mereka memperoleh jawaban 'Bagimu yang kau lihat dan semisalnya'.\" [Hajjaj bin Minhal] berkata; telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dari [Anas] radliyallahu'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: 'Pada hari kiamat nanti orang-orang mukmin ditahan hingga yang demikian menjadikan mereka sedih. Mereka katakan, 'Duh, sekiranya kita meminta syafaat kepada Tuhan kami sehingga Dia menjadikan kita merasa nyaman dari tempat kita ini.' Mereka pun mendatangi Adam dan berkata, 'Engkau hai Adam, Engkau adalah nenek moyang seluruh manusia, Allah menciptamu dengan tangan-Nya, menjadikan surga sebagai tempat hunianmu dan menjadikan malaikat bertunduk sujud kepadamu, Allah juga mengajarimu nama-nama segala sesuatu agar engkau bisa memberi syafaat kepada kami disisi Tuhanmu sehingga engkau bisa memberi kenyamanan di tempat kami ini. Namun Adam hanya menjawab, 'Disini saya tak berhak memberi syafaat untuk kalian'.\" Rasulullah melanjutkan: \"Lantas Adam mengingatkan kesalahan yang pernah dilakukannya, yaitu memakan pohon larangan padahal telah dilarang, dan ia katakan 'Coba kalian datangi Nuh, sebab ia adalah nabi shallallahu 'alaihi wasallam pertama-tama yang Allah utus kepada penduduk bumi.' Mereka pun mendatangi Nuh, namun Nuh juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', dan Nuh menyebutkan kesalahan yang pernah dilakukannya, yaitu bertanya kepada Rabbnya dengan tanpa ilmu sambil ia katakan, 'Cobalah kalian datangi Ibrahim, sebab ia adalah Khalilurrahman (kekasih Arrahman).\" Rasulullah melanjutkan lagi kisahnya: \"Mereka pun mendatangi Ibrahim, hanya Ibrahim juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', Ibrahim lantas menyebutkan kesalahannya, yaitu tiga kebohongan yang pernah dilakukannya sambil berkata, 'Cobalah kalian datangi Musa, seorang hamba yang Allah memberinya taurat, mengajaknya bicara dan mendekatkannya kepada-Nya sedekat-dekatnya'.\" Rasulullah lanjutkan: \"Mereka pun mendatangi Musa, hanya Musa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil Musa mengingatkan kesalahan yang pernah dilakukannya, yaitu membunuh jiwa tanpa alasan yang dibenarkan, sambil ia katakan, 'Coba kalian datangi Isa, seorang hamba Allah dan rasul-Nya, ruh Allah dan kalimah-Nya. Merekapun mendatangi Isa, namun 'Isa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil ia katakan 'Cobalah kalian datangi Muhammad Shallallahu'alaihiwasallam, seorang hamba yang Allah telah mengampuni dosanya yang terdahulu dan yang akan datang.' Lantas mereka mendatangi aku (Muhammad) dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud, Allah lalu membiarkan aku sekehendak Dia membiarkaku. Allah lantas berkata, 'Angkat kepalamu hai Muhammad, katakanlah, engkau didengar, mintailah syafaat, engkau diberi syafaat, mintalah, engkau diberi.' Aku lalu angkat kepalaku dan aku memuji Tuhanku dengan pujian yang Ia ajarkannya kepadaku, kemudian aku memberi syafaat dan Dia memberiku batasan. Kemudian aku keluar dan memasukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku juga mendengarnya menyebutkan, \"Aku lalu keluar, kemudian aku keluarkan mereka dari neraka dan kumasukkan ke dalam surga. Setelah itu aku kembali untuk kali kedua dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan untuk menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud. Allah lantas membiarkanku sekehendak Allah membiarkan, kemudian Allah berkata, 'Angkatlah kepalamu hai Muhammad dan katakanlah engkau akan didengar, dan berilah syafaat engkau akan diberi syafaat, dan mintalah engkau akan diberi.' Aku lalu angkat kepalaku dan memanjatkan pujian dan pujaan terhadap tuhanku sebagaimana yang diajakrkan-Nya kepadaku. Kemudian aku memberi syafaat, dan Ia memberiku batasan sehingga aku keluar dan aku masukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, \"Dan aku berangkat sehingga aku keluarkan mereka dari neraka, lalu mereka aku masukkan ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, 'Maka aku berangkat dan aku keluarkan mereka dari neraka, untuk kemudian aku masukkan mereka ke dalam surga, hingga tidak tersisa dalam neraka selain yang digi ditahan oleh alquran, atau maksudnya ia wajib abadi, kemudian beliau membaca ayat ini '(semoga Tuhanmu membangkitkankmu di tempat yang terpuji) ' (Qs. Al Isra': 79). Nabi mengatakan, \"Inilah maqam terpuji yang dijanjikan untuk nabi shallallahu 'alaihi wasallam kalian.\""}],"17:81":[{"p":"Bukhari","n":2298,"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا ابْنُ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَحَوْلَ الْكَعْبَةِ ثَلَاثُ مِائَةٍ وَسِتُّونَ نُصُبًا فَجَعَلَ يَطْعُنُهَا بِعُودٍ فِي يَدِهِ وَجَعَلَ يَقُولُ{ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ }الْآيَةَ","trj":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ibnu Abi Najih] dari [Mujahid] dari [Abu Ma'mar] dari ['Abdullah bin Mas'ud radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam masuk ke Ka'bah saat yang ketika itu berisi tiga ratus enam puluh patung, lalu Beliau menusuk dan menghancurkannya dengan menggunakan tongkat yang ada di tangan Beliau seraya berkata: \"Telah datang kebenaran dan sirnalah kebathilan\", QS Al Isra' ayat 81."},{"p":"Muslim","n":3100,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ وَابْنُ أَبِي عُمَرَ وَاللَّفْظُ لِابْنِ أَبِي شَيْبَةَ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَحَوْلَ الْكَعْبَةِ ثَلَاثُ مِائَةٍ وَسِتُّونَ نُصُبًا فَجَعَلَ يَطْعُنُهَا بِعُودٍ كَانَ بِيَدِهِ وَيَقُولُ{ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ إِنَّ الْبَاطِلَ كَانَ زَهُوقًا }{ جَاءَ الْحَقُّ وَمَا يُبْدِئُ الْبَاطِلُ وَمَا يُعِيدُ }زَادَ ابْنُ أَبِي عُمَرَ يَوْمَ الْفَتْحِو حَدَّثَنَاه حَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ كِلَاهُمَا عَنْ عَبْدِ الرَّزَّاقِ أَخْبَرَنَا الثَّوْرِيُّ عَنْ ابْنِ أَبِي نَجِيحٍ بِهَذَا الْإِسْنَادِ إِلَى قَوْلِهِ زَهُوقًا وَلَمْ يَذْكُرْ الْآيَةَ الْأُخْرَى وَقَالَ بَدَلَ نُصُبًا صَنَمًا","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan ['Amru An Naqid] serta [Ibnu Abu Umar] sedangkan lafadznya dari Ibnu Abu Syaibah, mereka berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ibnu Abu Najih] dari [Mujahid] dari [Abu Ma'mar] dari [Abdullah] dia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam masuk Makkah, saat itu terdapat tiga ratus enam puluh patung di sekitar Ka'bah. Lantas dengan tongkatnya beliau memukul patung tersebut sambil membaca: \"Telah datang kebenaran dan lenyaplah kebatilan, sesungguhnya kebatilan pasti lenyap…) ' (Qs. Al Israa: 81) '(Kebenaran telah datang dan yang batil itu tidak akan memulai dan tidak (pula) akan mengulangi) ' (Qs. Sabaa: 49). Ibnu Abu Umar menambahkan, \"Ketika hari penaklukan Kota Makkah.\" Dan telah menceritakan kepada kami [Hasan bin Ali Al Khulwani] dan [Abd bin Humaid] keduanya dari [Abdurrazaq] telah mengabarkan kepada kami [At Tsauri] dari [Ibnu Abu Najih] dengan isnad ini hingga perkataan, \"(dan kebatilan) itu pasti lenyap.\" Dan tidak menyebutkan ayat yang lain, dia juga berkata, \"Arca\" sebagai ganti dari \"Patung.\""}],"17:85":[{"p":"Bukhari","n":122,"ar":"حَدَّثَنَا قَيْسُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا الْأَعْمَشُ سُلَيْمَانُ بْنُ مِهْرَانَ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَبَيْنَا أَنَا أَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خَرِبِ الْمَدِينَةِ وَهُوَ يَتَوَكَّأُ عَلَى عَسِيبٍ مَعَهُ فَمَرَّ بِنَفَرٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ لِبَعْضٍ سَلُوهُ عَنْ الرُّوحِ وَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ لَا يَجِيءُ فِيهِ بِشَيْءٍ تَكْرَهُونَهُ فَقَالَ بَعْضُهُمْ لَنَسْأَلَنَّهُ فَقَامَ رَجُلٌ مِنْهُمْ فَقَالَ يَا أَبَا الْقَاسِمِ مَا الرُّوحُ فَسَكَتَ فَقُلْتُ إِنَّهُ يُوحَى إِلَيْهِ فَقُمْتُ فَلَمَّا انْجَلَى عَنْهُ قَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي }وَمَا أُوتُوا مِنْ الْعِلْمِ إِلَّا قَلِيلًاقَالَ الْأَعْمَشُ هَكَذَا فِي قِرَاءَتِنَا","trj":"Telah menceritakan kepada kami [Qais bin Hafsh] berkata, telah menceritakan kepada kami ['Abdul Wahid] berkata, telah menceritakan kepada kami [Al A'masy Sulaiman bin Mihran] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] berkata, \"Ketika aku berjalan bersama Nabi shallallahu 'alaihi wasallam di sekitar pinggiran Kota Madinah, saat itu beliau membawa tongkat dari batang pohon kurma. Beliau lalu melewati sekumpulan orang Yahudi, maka sesama mereka saling berkata, \"Tanyakanlah kepadanya tentang ruh!\" Sebagian yang lain berkata, \"Janganlah kalian bicara dengannya hingga ia akan mengatakan sesuatu yang kalian tidak menyukainya.\" Lalu sebagian yang lain berkata, \"Sungguh, kami benar-benar akan bertanya kepadanya.\" Maka berdirilah seorang laki-laki dari mereka seraya bertanya, \"Wahai Abul Qasim, ruh itu apa?\" Beliau diam. Maka aku pun bergumam, \"Sesungguhnya beliau sedang menerima wahyu.\" Ketika orang itu berpaling, beliau pun membaca: '(Dan mereka bertanya kepadamu tentang ruh. Katakanlah: \"Ruh itu termasuk urusan Rabbku, dan tidaklah kamu diberi pengetahuan melainkan sedikit) ' (Qs. Al Israa`: 85). Al A'masy berkata, \"Seperti inilah dalam qira`ah kami.\""},{"p":"Bukhari","n":6413,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرْثٍ بِالْمَدِينَةِ وَهُوَ يَتَوَكَّأُ عَلَى عَسِيبٍ فَمَرَّ بِنَفَرٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ سَلُوهُ عَنْ الرُّوحِ وَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ لَا يُسْمِعُكُمْ مَا تَكْرَهُونَ فَقَامُوا إِلَيْهِ فَقَالُوا يَا أَبَا الْقَاسِمِ حَدِّثْنَا عَنْ الرُّوحِ فَقَامَ سَاعَةً يَنْظُرُ فَعَرَفْتُ أَنَّهُ يُوحَى إِلَيْهِ فَتَأَخَّرْتُ عَنْهُ حَتَّى صَعِدَ الْوَحْيُ ثُمَّ قَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي }","trj":"Telah menceritakan kepada kami [Muhammad bin Ubaid bin Maimun] telah menceritakan kepada kami ['Isa bin Yunus] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Ibn Mas'ud] rahiyallahu'anhu berkata, \"Pernah aku bersama nabi shallallahu 'alaihi wasallam di sebuah kebun Madinah sedang beliau menyandarkan punggung, lantas beberapa orang Yahudi lewat, dan sebagian mereka mengatakan 'Coba tanyailah dia tentang roh! ' Sebagian berkata 'Jangan kalian tanyai dia tentang itu, sebab yang kalian benci tidak bisa memperdengarkan kepada kalian.' Namun sebagian mereka berdiri dan bertanya \"Wahai Abul Qasim, beritahukanlah kami tentang roh! ' Lantas beliau berdiri beberapa saat mengamat-amati, maka aku tahu bahwa beliau sedang menerima wahyu, maka aku berusaha menyingkir dari beliau, hingga wahyu terangkat, kemudian beliau bersabda mengutip ayat: '(Mereka bertanya kepadamu tentang roh, katakanlah bahwa roh itu urusan Rabbiku) ' (Qs. Al Israa`: 85)."},{"p":"Bukhari","n":6547,"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَكُنْتُ أَمْشِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرْثٍ بِالْمَدِينَةِ وَهُوَ مُتَّكِئٌ عَلَى عَسِيبٍ فَمَرَّ بِقَوْمٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ لِبَعْضٍ سَلُوهُ عَنْ الرُّوحِ وَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ عَنْ الرُّوحِ فَسَأَلُوهُ فَقَامَ مُتَوَكِّئًا عَلَى الْعَسِيبِ وَأَنَا خَلْفَهُ فَظَنَنْتُ أَنَّهُ يُوحَى إِلَيْهِ فَقَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي وَمَا أُوتِيتُمْ مِنْ الْعِلْمِ إِلَّا قَلِيلًا }فَقَالَ بَعْضُهُمْ لِبَعْضٍ قَدْ قُلْنَا لَكُمْ لَا تَسْأَلُوهُ","trj":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] berkata, \"Pernah aku berjalan bersama Rasulullah shallallahu 'alaihi wasallam di sebuah kebun di Madinah, saat beliau bertelekan di atas tongkat. Kemudian beliau melewati sekelompok orang Yahudi, sebagian diantara mereka bertanya kepada sebagian lainnya 'Coba tanyailah dia tentang nyawa', sedang sebagian lain berkata 'Jangan tanyai dia tentang nyawa'. Kemudian beliau berdiri bertelekan di atas tongkatnya sedang saya berada di belakangnya, aku taksir beliau sedang menerima wahyu, lantas beliau membacakan kepada mereka: '(Dan mereka bertanya kepadamu tentang nyawa, katakanlah bahwa nyawa itu adalah urusan tuhanku, dan tidaklah kamu diberi ilmu melainkan sedikit) ' (Qs. Al Isra': 85). Maka sebagian di antara mereka berkata kepada sebagian lainnya, 'Kan telah kami katakan kepada kalian, jangan kalian tanya tentangnya! '"},{"p":"Bukhari","n":6553,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ عَنْ عَبْدِ الْوَاحِدِ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ ابْنِ مَسْعُودٍ قَالَبَيْنَا أَنَا أَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ حَرْثِ الْمَدِينَةِ وَهُوَ يَتَوَكَّأُ عَلَى عَسِيبٍ مَعَهُ فَمَرَرْنَا عَلَى نَفَرٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ لِبَعْضٍ سَلُوهُ عَنْ الرُّوحِ فَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ أَنْ يَجِيءَ فِيهِ بِشَيْءٍ تَكْرَهُونَهُ فَقَالَ بَعْضُهُمْ لَنَسْأَلَنَّهُ فَقَامَ إِلَيْهِ رَجُلٌ مِنْهُمْ فَقَالَ يَا أَبَا الْقَاسِمِ مَا الرُّوحُ فَسَكَتَ عَنْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلِمْتُ أَنَّهُ يُوحَى إِلَيْهِ فَقَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي }وَمَا أُوتُوا مِنْ الْعِلْمِ إِلَّا قَلِيلًاقَالَ الْأَعْمَشُ هَكَذَا فِي قِرَاءَتِنَا","trj":"Telah menceritakan kepada kami [Musa bin Ismail] dari [Abdul Wahid] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Ibnu Mas'ud] berkata, \"Pernah aku berjalan bersama nabi shallallahu 'alaihi wasallam di sebagian kebun Madinah, sedang ketika itu beliau bersandar di atas sebuah dahan pohon kurma, saat kami melewati beberapa orang Yahudi, sebagian mereka berkata kepada sebagian lainnya, 'Tolong tanyailah dia (Muhammad) tentang nyawa', sementara sebagian mereka berkata, 'Jangan engkau bertanya kepadanya suatu hal yang kalian sendiri ketakutan terhadapnya'. Namun sebagian mereka ngotot berkata, 'Sungguh kami akan bertanya kepadanya! ' Lalu sebagian di antara mereka datang menemui beliau dan berkata, \"Wahai abu Qasim, apa nyawa itu?\" Nabi shallallhu'lihiwasallam terdiam, maka aku pun tahu bahwa beliau sedang menerima wahyu. Lantas beliau membacakan ayat: '(Dan mereka bertanya kepadamu tentang nyawa, katakanlah 'Bahwasanya nyawa itu urusan Tuhanku, dan tidaklah kalian diberi ilmu kecuali sedikit saja) ' (Qs. Al Isra': 85)."}],"17:93":[{"p":"Bukhari","n":3409,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ أَوْ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى قَالَ سَلْ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ مَا أَمْرُهُمَا{ وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ لَمَّا أُنْزِلَتْ الَّتِي فِي الْفُرْقَانِ قَالَ مُشْرِكُو أَهْلِ مَكَّةَ فَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَقَدْ أَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ }الْآيَةَ فَهَذِهِ لِأُولَئِكَ وَأَمَّا الَّتِي فِي النِّسَاءِ الرَّجُلُ إِذَا عَرَفَ الْإِسْلَامَ وَشَرَائِعَهُ ثُمَّ قَتَلَ فَجَزَاؤُهُ جَهَنَّمُفَذَكَرْتُهُ لِمُجَاهِدٍ فَقَالَإِلَّا مَنْ نَدِمَ","trj":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] telah menceritakan kepadaku [Sa'id bin Jubair] -atau dia berkata, telah menceritakan kepadaku [Al Hakam] dari [Sa'id bin Jubair] berkata, - 'Abdurrahman bin Abza menyuruhku, katanya; \"Tanyalah kepada Ibnu 'Abbas tentang dua ayat ini dan apa maksudnya, yaitu yang pertama firman Allah dalam QS al Isra` ayat 33; (\"Dan janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan haq (alasan yang benar) \" dan yang kedua firman Allah dalam QS an Nisaa' ayat 93: (\"Dan barangsiapa yang membunuh orang beriman dengan sengaja...\"). Maka aku bertanya kepada [Ibnu 'Abbas], maka dia menjelaskan; Ketika turun firman Allah yang serupa ini pada surah al Furqan, orang-orang musyrik penduduk Makkah berkata; \"Sungguh kita telah membunuh jiwa yang diharamkan Allah dan kita juga menyembah selain Allah dan kita telah banyak berbuat maksiat, maka Allah menurunkan firman-Nya yang artinya: \"...kecuali siapa yang bertaubat dan beriman...\" (QS al Furqan ayat 70). Nah, ayat-ayat ini turun untuk mereka. Adapun ayat yang ada dalam surah an Nisaa' adalah bila seseorang telah mengenal Islam dan syari'atnya, kemudian dia membunuh seseorang dengan sengaja maka balasan baginya adalah neraka jahannam\". Kemudian keterangan ini aku sampaikan kepada Mujahidmaka dia berkata; \"Kecuali siapa yang menyesali perbuartannya\"."}],"17:101":[{"p":"Ahmad","n":1980,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ وَحَدَّثَنَاهُ يَزِيدُ أَخْبَرَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ سَلَمَةَ يُحَدِّثُ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَ يَزِيدُ الْمُرَادِيِّ قَالَقَالَ يَهُودِيٌّ لِصَاحِبِهِ اذْهَبْ بِنَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ يَزِيدُ إِلَى هَذَا النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى نَسْأَلَهُ عَنْ هَذِهِ الْآيَةِ{ وَلَقَدْ آتَيْنَا مُوسَى تِسْعَ آيَاتٍ }فَقَالَ لَا تَقُلْ لَهُ نَبِيٌّ فَإِنَّهُ إِنْ سَمِعَكَ لَصَارَتْ لَهُ أَرْبَعَةُ أَعْيُنٍ فَسَأَلَاهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا تَسْحَرُوا وَلَا تَأْكُلُوا الرِّبَا وَلَا تَمْشُوا بِبَرِيءٍ إِلَى ذِي سُلْطَانٍ لِيَقْتُلَهُ وَلَا تَقْذِفُوا مُحْصَنَةً أَوْ قَالَ تَفِرُّوا مِنْ الزَّحْفِ شُعْبَةُ الشَّاكُّ وَأَنْتُمْ يَا يَهُودُ عَلَيْكُمْ خَاصَّةً أَنْ لَا تَعْتَدُوا قَالَ يَزِيدُ تَعْدُوا فِي السَّبْتِ فَقَبَّلَا يَدَهُ وَرِجْلَهُ قَالَ يَزِيدُ يَدَيْهِ وَرِجْلَيْهِ وَقَالَا نَشْهَدُ أَنَّكَ نَبِيٌّ قَالَ فَمَا يَمْنَعُكُمَا أَنْ تَتَّبِعَانِي قَالَا إِنَّ دَاوُدَ عَلَيْهِ السَّلَام دَعَا أَنْ لَا يَزَالَ مِنْ ذُرِّيَّتِهِ نَبِيٌّ وَإِنَّا نَخْشَى قَالَ يَزِيدُ إِنْ أَسْلَمْنَا أَنْ تَقْتُلَنَا يَهُودُ","trj":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dan telah menceritakannya kepada kami [Yazid] telah mengabarkan kepada kami [Syu'bah] dari [Amru bin Murrah] ia berkata, saya mendengar [Abdullah bin Salamah] menceritakan dari [Shafwan bin Assal] berkata, [Yazid Al Muradi] berkata, \"Seorang Yahudi berkata kepada sahabatnya, \"Berangkatlah bersama kami untuk menemui Nabi shallallahu 'alaihi wasallam.\" Yazid menyebutkan, \"Kepada Nabi ini shallallahu 'alaihi wasallam hingga kita bisa bertanya kepadanya tentang ayat ini: '(Sungguh kita telah datang kepada Musa dengan sembilan ayat) '\" (Qs. Al Isra`: 101). Maka temannya itu berkata, \"Jangan kamu katakan bahwa ia adalah seorang Nabi! Sungguh jika ia mendengarmu maka ia akan mempunyai empat buah mata.\" Kemudian keduanya pun bertanya kepada Nabi shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menyekutukan Allah dengan sesuatu apapun, janganlah kalian mencuri, janganlah kalian berzina, janganlah kalian membunuh jiwa yang diharamkan oleh Allah kecuali dengan hak, janganlah kalian melakukan sihir, janganlah kalian memakan riba, janganlah kalian mengadukan seorang yang tidak bersalah kepada penguasa agar ia membunuhnya, dan janganlah kalian menuduh berbuat zina wanita yang suci dan tidak pernah melakukannya. Atau beliau mengatakan: \"Janganlah kalian lari dari peperangan -Syu'bah masih merasa ragu-. Dsan khusus bagi kalian wahai orang-orang Yahudi, janganlah kalian melanggar larangan.\" Yazid berkata, \"Maksudnya melanggar larangan (mencari ikan) pada hari sabtu. Kemudian kedua orang Yahudi itu pun mencium tangan dan kaki beliau.\" Yazid menyebutkan, \"Kedua tangan dan kedua kaki beliau, lalu keduanya berkata, \"Kami bersaksi bahwa anda adalah seorang Nabi.\" Nabi shallallahu 'alaihi wasallam lantas bertanya: \"Lalu apa yang menghalangi kalian berdua untuk mengikutiku?\" Kedua orang itu berkata, \"Sesungguhnya Dawud 'Alaihissalam pernah berdoa agar di antara keturunannya ada yang masih bisa menjadi Nabi. Jika kami masuk Islam, maka kami khawatir orang-orang Yahudi akan membunuh kami.\""},{"p":"Ahmad","n":1984,"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَمَةَ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَقَالَ رَجُلٌ مِنْ الْيَهُودِ لِآخَرَ انْطَلِقْ بِنَا إِلَى هَذَا النَّبِيِّ قَالَ لَا تَقُلْ هَذَا فَإِنَّهُ لَوْ سَمِعَهَا كَانَ لَهُ أَرْبَعُ أَعْيُنٍ قَالَ فَانْطَلَقْنَا إِلَيْهِ فَسَأَلْنَاهُ عَنْ هَذِهِ الْآيَةِ{ وَلَقَدْ آتَيْنَا مُوسَى تِسْعَ آيَاتٍ بَيِّنَاتٍ }قَالَ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَفِرُّوا مِنْ الزَّحْفِ وَلَا تَسْحَرُوا وَلَا تَأْكُلُوا الرِّبَا وَلَا تُدْلُوا بِبَرِيءٍ إِلَى ذِي سُلْطَانٍ لِيَقْتُلَهُ وَعَلَيْكُمْ خَاصَّةً يَهُودُ أَنْ لَا تَعْتَدُوا فِي السَّبْتِ فَقَالَا نَشْهَدُ إِنَّكَ رَسُولُ اللَّهِ","trj":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] telah menceritakan kepadaku [Amru bin Murrah] dari [Abdullah bin Salamah] dari [Shafwan bin Assal] ia berkata, \"Seorang laki-laki Yahudi berkata kepada temannya, \"Marilah bersama-sama berangkat menemui Nabi ini (Muhammad).\" Temannya itu menjawab, \"Jangan kamu mengatakan seperti ini, karena jika ia mendengarnya maka ia akan memiliki empat mata.\" Orang Yahudi itu berkata, \"Maka kami pun berangkat menemui beliau dan betanya mengenai ayat ini: '(Dan sungguh, Kami telah memberikan kepada Musa sembilan ayat) ' (Qs. Al Isra`: 101). Maka beliau menjawab: \"Janganlah kalian menyekutukan Allah dengan sesuatu apapun, jangan membunuh jiwa yang diharamkan oleh Allah kecuali dengan hak, jangan mencuri, jangan berzina, jangan lari dari medan pertempuran, jangan melakukan sihir, jangan memakan riba, dan janganlah kalian menyerahkan orang yang tidak bersalah kepada penguasa hingga ia membunuhnya. Dan khusus bagi kalian hai orang-orang Yahudi! Janganlah kalian melanggar larangan (mencari ikan) pada hari sabtu.\" Maka kedua orang Yahudi itu pun berkata, \"Kami bersaksi bahwa anda adalah Rasulullah.\""}],"17:107":[{"p":"Darimi","n":212,"ar":" أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ أَبِي أُسَامَةَ عَنْ مِسْعَرٍ قَالَ سَمِعْتُ عَبْدَ الْأَعْلَى التَّيْمِيَّ يَقُولُ مَنْ أُوتِيَ مِنْ الْعِلْمِ مَا لَا يُبْكِيهِ لَخَلِيقٌ أَنْ لَا يَكُونَ أُوتِيَ عِلْمًا يَنْفَعُهُ لِأَنَّ اللَّهَ تَعَالَى نَعَتَ الْعُلَمَاءَ ثُمَّ قَرَأَ الْقُرْآنَ { إِنَّ الَّذِينَ أُوتُوا الْعِلْمَ إِلَى قَوْلِهِ يَبْكُونَ }","trj":"Telah mengabarkan kepada kami [Sa'id bin Sulaiman] dari [Abu Usamah] dari [Mis'ar] ia berkata: \"Aku pernah mendengar [Abdul A'la At Taimi] berkata: 'Barangsiapa yang dianugerahi ilmu dan ilmunya tidak membuatnya menangis kepada Allah, berarti ia mendapatkan ilmu yang tidak bermanfaat, karena Allah mensifati para ulama, kemudian ia membaca Al Qur`an: INNALLADZIINA UUTUL 'ILMA\" (sesungguhnya orang-orang yang dianugerahi ilmu) sampai firmanNya: \"YABKUUN\" (mereka selalu menangis) -Qs. Al Isra`: 107-108-' \"."}],"17:108":[{"p":"Darimi","n":212,"ar":" أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ أَبِي أُسَامَةَ عَنْ مِسْعَرٍ قَالَ سَمِعْتُ عَبْدَ الْأَعْلَى التَّيْمِيَّ يَقُولُ مَنْ أُوتِيَ مِنْ الْعِلْمِ مَا لَا يُبْكِيهِ لَخَلِيقٌ أَنْ لَا يَكُونَ أُوتِيَ عِلْمًا يَنْفَعُهُ لِأَنَّ اللَّهَ تَعَالَى نَعَتَ الْعُلَمَاءَ ثُمَّ قَرَأَ الْقُرْآنَ { إِنَّ الَّذِينَ أُوتُوا الْعِلْمَ إِلَى قَوْلِهِ يَبْكُونَ }","trj":"Telah mengabarkan kepada kami [Sa'id bin Sulaiman] dari [Abu Usamah] dari [Mis'ar] ia berkata: \"Aku pernah mendengar [Abdul A'la At Taimi] berkata: 'Barangsiapa yang dianugerahi ilmu dan ilmunya tidak membuatnya menangis kepada Allah, berarti ia mendapatkan ilmu yang tidak bermanfaat, karena Allah mensifati para ulama, kemudian ia membaca Al Qur`an: INNALLADZIINA UUTUL 'ILMA\" (sesungguhnya orang-orang yang dianugerahi ilmu) sampai firmanNya: \"YABKUUN\" (mereka selalu menangis) -Qs. Al Isra`: 107-108-' \"."}],"17:110":[{"p":"Bukhari","n":6574,"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ هُشَيْمٍ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }قَالَ أُنْزِلَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَوَارٍ بِمَكَّةَ فَكَانَ إِذَا رَفَعَ صَوْتَهُ سَمِعَ الْمُشْرِكُونَ فَسَبُّوا الْقُرْآنَ وَمَنْ أَنْزَلَهُ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ تَعَالَى{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }{ لَا تَجْهَرْ بِصَلَاتِكَ }حَتَّى يَسْمَعَ الْمُشْرِكُونَ{ وَلَا تُخَافِتْ بِهَا }عَنْ أَصْحَابِكَ فَلَا تُسْمِعُهُمْ{ وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }أَسْمِعْهُمْ وَلَا تَجْهَرْ حَتَّى يَأْخُذُوا عَنْكَ الْقُرْآنَ","trj":"Telah menceritakan kepada kami [Musaddad] dari [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibn Abbas] mengenai ayat: '(Dan janganlah engkau mengeraskan bacaan shalatmu dan jangan pula engkau merendahkan bacaannya) ' (Qs. Al Isra': 110), ayat ini diturunkan kepada Rasulullah shallallahu 'alaihi wasallam secara berturut-turut di Makkah. Ketika itu, jika beliau mengencangkan bacaannya, maka kaum musyrikin mendengarnya hingga mereka mencela Al Qur'an secara habis-habisan, juga mencela yang menurunkannya dan yang membawanya. Maka Allah menurunkan: '(Jangan kamu mengeraskan bacaan shalatmu dan jangan pula merendahkannya) ' (Qs. Al Isra': 110). Jangan kamu mengeraskan bacaanmu maksudnya hingga terdengar oleh orang-orang musyrik, dan jangan pula kamu merendahkannya, maksudnya sehingga tidak terdengar oleh kawan-kawanmu. Dan carilah jalan tengah di antara keduanya, maksudnya bacalah sehingga terdengar oleh kawanmu namun jangan pula kamu membaca terlalu keras hingga musuh mencela Al Qur'an akibat bacaanmu.\""},{"p":"Bukhari","n":6601,"ar":"حَدَّثَنِي عَمْرُو بْنُ زُرَارَةَ عَنْ هُشَيْمٍ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَافِي قَوْلِهِ تَعَالَى{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }قَالَ نَزَلَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُخْتَفٍ بِمَكَّةَ فَكَانَ إِذَا صَلَّى بِأَصْحَابِهِ رَفَعَ صَوْتَهُ بِالْقُرْآنِ فَإِذَا سَمِعَهُ الْمُشْرِكُونَ سَبُّوا الْقُرْآنَ وَمَنْ أَنْزَلَهُ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ }أَيْ بِقِرَاءَتِكَ فَيَسْمَعَ الْمُشْرِكُونَ فَيَسُبُّوا الْقُرْآنَ{ وَلَا تُخَافِتْ بِهَا }عَنْ أَصْحَابِكَ فَلَا تُسْمِعُهُمْ{ وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }","trj":"Telah menceritakan kepadaku ['Amru bin Zurarah] dari [Husyaim] telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibn Abbas] radliyallahu'anhuma tentang firman Allah Ta'ala: '(Jangan kamu membacanya secara lantang dalam shalatmu, dan jangan pula secara lirih) ' (Qs. Al Isra': ayat 110), Ibn Abbas berkata, \"Ayat ini diturunkan saat Rasulullah shallallahu 'alaihi wasallam masih sembunyi-sembunyi di Makkah, jika shalat bersama sahabat-sahabatnya, beliau mengeraskan bacaan Al Qur'annya, sehingga jika kaum musyrikin mendengarnya, mereka mencaci Al Qur'an, Dzat yang menurunkannya dan malaikat yang membawanya. Maka Allah menegur nabi-Nya shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam dengan ayat: '(Jangan kamu membacanya secara lantang dalam shalatmu) ' (Qs. Al Isra': ayat 110), yakni dengan bacaanmu, sehingga saat orang-orang Musyrik mendengar mereka akan mencela Al Qur'an, '(dan jangan pula secara lirih), yaitu kepada para sahabatmu, sehingga engkau tidak bisa menjadikan mereka mendengar, (Carilah jalan tengah antara keduanya) ', (Qs. Al Isra: ayat 110)."},{"p":"Bukhari","n":6602,"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْنَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }فِي الدُّعَاءِ","trj":"Telah menceritakan kepada kami [Ubaid bin Ismail] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Ayahnya] dari [Aisyah] radliyallahu'anha, ia berkata, \"Ayat ini: '(Janganlah kamu menyaringkan bacaanmu ketika shalatmu dan jangan pula membacanya terlalu lirih) ', (Qs. Al Isra`: Ayat 110), diturunkan berkenaan dengan doa.\""},{"p":"Bukhari","n":6622,"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَوَارِيًا بِمَكَّةَ وَكَانَ يَرْفَعُ صَوْتَهُ فَإِذَا سَمِعَ الْمُشْرِكُونَ سَبُّوا الْقُرْآنَ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ عَزَّ وَجَلَّ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }","trj":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibn 'Abbas] radliyallahu'anhuma, ia berkata, \"Nabi Shallalahu'alaihiwasllam sembunyi-sembunyi di Makkah, namun beliau mengeraskan suara bacaan, saat orang-orang musyrik mendengar (suara bacaan beliau), mereka mencaci Al Qur'an dan orang yang membawanya. Maka Allah Azza wa Jalla pun menurunkan ayat kepada nabi-Nya: '(Dan janganlah engkau menyaringkan bacaan shalatmu dan jangan pula melirihkannya) ', (Qs. Al Isra': 110)."},{"p":"Malik","n":452,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَإِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }فِي الدُّعَاءِ","trj":"Telah menceritakan kepadaku dari Malik dari [Hisyam bin Urwah] dari [Bapaknya] bahwa dia berkata, \"Diturunkannya ayat ini: '(dan janganlah kamu mengeraskan suaramu dalam shalatmu dan janganlah pula merendahkannya dan carilah jalan tengah di antara kedua itu) ' (Qs. Al Israa`: 110) berkenaan dengan masalah doa.\""},{"p":"Nasa'i","n":999,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مَنِيعٍ وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ قَالَا حَدَّثَنَا هُشَيْمٌ قَالَ حَدَّثَنَا أَبُو بِشْرٍ جَعْفَرُ بْنُ أَبِي وَحْشِيَّةَ وَهُوَ ابْنُ إِيَاسٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }قَالَ نَزَلَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُخْتَفٍ بِمَكَّةَ فَكَانَ إِذَا صَلَّى بِأَصْحَابِهِ رَفَعَ صَوْتَهُ وَقَالَ ابْنُ مَنِيعٍ يَجْهَرُ بِالْقُرْآنِ وَكَانَ الْمُشْرِكُونَ إِذَا سَمِعُوا صَوْتَهُ سَبُّوا الْقُرْآنَ وَمَنْ أَنْزَلَهُ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ عَزَّ وَجَلَّ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ }أَيْ بِقِرَاءَتِكَ فَيَسْمَعَ الْمُشْرِكُونَ فَيَسُبُّوا الْقُرْآنَ{ وَلَا تُخَافِتْ بِهَا }عَنْ أَصْحَابِكَ فَلَا يَسْمَعُوا{ وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }","trj":"Telah mengabarkan kepada kami [Ahmad bin Mani'] dan [Ya'qub bin Ibrahim Ad-Dauraqiy] mereka berdua berkata; telah menceritakan kepada kami [Husyaim] dia berkata; telah menceritakan kepada kami [Abu Bisyr Ja'far bin Abu Wahsyiyyah bin Iyas] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] tentang firman Allah Azza wa Jalla, \"Janganlah kamu mengeraskan suaramu dalam shalatmu dan Janganlah pula merendahkannya.\" (Qs. Al Israa' (17): 1 10), dia berkata; \"Ayat ini turun dan Rasulullah Shallallahu'alaihi wasallam masih sembunyi-sembunyi dalam berdakwah di Makkah. Jika beliau mengerjakan shalat dengan para sahabatnya, maka beliau Shallallahu'alaihi wasallam mengeraskan suaranya, Ibnu Mani' berkata, \"Beliau memperdengarkan bacaan Al Qur'annya. Adalah orang-orang musyrik yang mendengar suara Rasulullah Shallallahu'alaihi wasallam (saat membaca Al Qur'an) mencela Al Qur'an, yang menurunkannya (Allah), serta yang membawanya (malaikat Jibril). Oleh karena itu Allah Azza wa Jalla berfirman kepada nabi-Nya, \"Janganlah kamu mengeraskan suaramu dalam shalatmu\" yakni dalam bacaannya. -Jika- Orang musyrik mendengar hal ini, maka mereka mencela Al Qur'an.\"Dan janganlah pula melirihkannya\" dari sahabatmu hingga mereka tidak mendengar.\"Dan carilah jalannya diantara keadaan yang demikian.\" (Qs. Al Israa' (17): 110)."}]},"mapping_surah":[{"p":"Abu Dawud","n":3775,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ إِيَادٍ حَدَّثَنَا إِيَادٌ عَنْ أَبِي رِمْثَةَ قَالَانْطَلَقْتُ مَعَ أَبِي نَحْوَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي ابْنُكَ هَذَا قَالَ إِي وَرَبِّ الْكَعْبَةِ قَالَ حَقًّا قَالَ أَشْهَدُ بِهِ قَالَ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَاحِكًا مِنْ ثَبْتِ شَبَهِي فِي أَبِي وَمِنْ حَلِفِ أَبِي عَلَيَّ ثُمَّ قَالَ أَمَا إِنَّهُ لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِ وَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }","trj":"Telah menceritakan kepada kami [Ahmad bin yunus] berkata, telah menceritakan kepada kami [Ubaidullah] -maksudnya Ubaidullah bin Iyad- berkata, telah menceritakan kepada kami [Iyad] dari [Abu Rimtsah] ia berkata; Aku dan bapakku berangkat menemui Nabi shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam bertanya kepada bapakku: \"Apakah ini anakmu?\" bapakku menjawab, \"Benar, demi Tuhannya Ka'bah.\" Beliau bertanya lagi: \"Apakah itu benar?\" bapakku menjawab, \"Aku bersaksi atasnya.\" Abu Rismtsah berkata, \"Rasulullah shallallahu 'alaihi wasallam lalu tersenyum karena aku mirip dengan bapakku dan karena sumpah yang dilakukannya atas diriku. Kemudian beliau bersabda: \"Ketahuilah, dia tidak akan memikul dosamu dan kamu tidak akan memikul dosanya.\" Lalu beliau membaca ayat: '(dan orang yang berdosa tidak akan memikul dosa orang lain) ' -Qs. Al Isra: 15-. "},{"p":"Ahmad","n":1980,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ وَحَدَّثَنَاهُ يَزِيدُ أَخْبَرَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ سَلَمَةَ يُحَدِّثُ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَ يَزِيدُ الْمُرَادِيِّ قَالَقَالَ يَهُودِيٌّ لِصَاحِبِهِ اذْهَبْ بِنَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ يَزِيدُ إِلَى هَذَا النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى نَسْأَلَهُ عَنْ هَذِهِ الْآيَةِ{ وَلَقَدْ آتَيْنَا مُوسَى تِسْعَ آيَاتٍ }فَقَالَ لَا تَقُلْ لَهُ نَبِيٌّ فَإِنَّهُ إِنْ سَمِعَكَ لَصَارَتْ لَهُ أَرْبَعَةُ أَعْيُنٍ فَسَأَلَاهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا تَسْحَرُوا وَلَا تَأْكُلُوا الرِّبَا وَلَا تَمْشُوا بِبَرِيءٍ إِلَى ذِي سُلْطَانٍ لِيَقْتُلَهُ وَلَا تَقْذِفُوا مُحْصَنَةً أَوْ قَالَ تَفِرُّوا مِنْ الزَّحْفِ شُعْبَةُ الشَّاكُّ وَأَنْتُمْ يَا يَهُودُ عَلَيْكُمْ خَاصَّةً أَنْ لَا تَعْتَدُوا قَالَ يَزِيدُ تَعْدُوا فِي السَّبْتِ فَقَبَّلَا يَدَهُ وَرِجْلَهُ قَالَ يَزِيدُ يَدَيْهِ وَرِجْلَيْهِ وَقَالَا نَشْهَدُ أَنَّكَ نَبِيٌّ قَالَ فَمَا يَمْنَعُكُمَا أَنْ تَتَّبِعَانِي قَالَا إِنَّ دَاوُدَ عَلَيْهِ السَّلَام دَعَا أَنْ لَا يَزَالَ مِنْ ذُرِّيَّتِهِ نَبِيٌّ وَإِنَّا نَخْشَى قَالَ يَزِيدُ إِنْ أَسْلَمْنَا أَنْ تَقْتُلَنَا يَهُودُ","trj":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dan telah menceritakannya kepada kami [Yazid] telah mengabarkan kepada kami [Syu'bah] dari [Amru bin Murrah] ia berkata, saya mendengar [Abdullah bin Salamah] menceritakan dari [Shafwan bin Assal] berkata, [Yazid Al Muradi] berkata, \"Seorang Yahudi berkata kepada sahabatnya, \"Berangkatlah bersama kami untuk menemui Nabi shallallahu 'alaihi wasallam.\" Yazid menyebutkan, \"Kepada Nabi ini shallallahu 'alaihi wasallam hingga kita bisa bertanya kepadanya tentang ayat ini: '(Sungguh kita telah datang kepada Musa dengan sembilan ayat) '\" (Qs. Al Isra`: 101). Maka temannya itu berkata, \"Jangan kamu katakan bahwa ia adalah seorang Nabi! Sungguh jika ia mendengarmu maka ia akan mempunyai empat buah mata.\" Kemudian keduanya pun bertanya kepada Nabi shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menyekutukan Allah dengan sesuatu apapun, janganlah kalian mencuri, janganlah kalian berzina, janganlah kalian membunuh jiwa yang diharamkan oleh Allah kecuali dengan hak, janganlah kalian melakukan sihir, janganlah kalian memakan riba, janganlah kalian mengadukan seorang yang tidak bersalah kepada penguasa agar ia membunuhnya, dan janganlah kalian menuduh berbuat zina wanita yang suci dan tidak pernah melakukannya. Atau beliau mengatakan: \"Janganlah kalian lari dari peperangan -Syu'bah masih merasa ragu-. Dsan khusus bagi kalian wahai orang-orang Yahudi, janganlah kalian melanggar larangan.\" Yazid berkata, \"Maksudnya melanggar larangan (mencari ikan) pada hari sabtu. Kemudian kedua orang Yahudi itu pun mencium tangan dan kaki beliau.\" Yazid menyebutkan, \"Kedua tangan dan kedua kaki beliau, lalu keduanya berkata, \"Kami bersaksi bahwa anda adalah seorang Nabi.\" Nabi shallallahu 'alaihi wasallam lantas bertanya: \"Lalu apa yang menghalangi kalian berdua untuk mengikutiku?\" Kedua orang itu berkata, \"Sesungguhnya Dawud 'Alaihissalam pernah berdoa agar di antara keturunannya ada yang masih bisa menjadi Nabi. Jika kami masuk Islam, maka kami khawatir orang-orang Yahudi akan membunuh kami.\""},{"p":"Ahmad","n":1984,"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَمَةَ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَقَالَ رَجُلٌ مِنْ الْيَهُودِ لِآخَرَ انْطَلِقْ بِنَا إِلَى هَذَا النَّبِيِّ قَالَ لَا تَقُلْ هَذَا فَإِنَّهُ لَوْ سَمِعَهَا كَانَ لَهُ أَرْبَعُ أَعْيُنٍ قَالَ فَانْطَلَقْنَا إِلَيْهِ فَسَأَلْنَاهُ عَنْ هَذِهِ الْآيَةِ{ وَلَقَدْ آتَيْنَا مُوسَى تِسْعَ آيَاتٍ بَيِّنَاتٍ }قَالَ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَفِرُّوا مِنْ الزَّحْفِ وَلَا تَسْحَرُوا وَلَا تَأْكُلُوا الرِّبَا وَلَا تُدْلُوا بِبَرِيءٍ إِلَى ذِي سُلْطَانٍ لِيَقْتُلَهُ وَعَلَيْكُمْ خَاصَّةً يَهُودُ أَنْ لَا تَعْتَدُوا فِي السَّبْتِ فَقَالَا نَشْهَدُ إِنَّكَ رَسُولُ اللَّهِ","trj":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] telah menceritakan kepadaku [Amru bin Murrah] dari [Abdullah bin Salamah] dari [Shafwan bin Assal] ia berkata, \"Seorang laki-laki Yahudi berkata kepada temannya, \"Marilah bersama-sama berangkat menemui Nabi ini (Muhammad).\" Temannya itu menjawab, \"Jangan kamu mengatakan seperti ini, karena jika ia mendengarnya maka ia akan memiliki empat mata.\" Orang Yahudi itu berkata, \"Maka kami pun berangkat menemui beliau dan betanya mengenai ayat ini: '(Dan sungguh, Kami telah memberikan kepada Musa sembilan ayat) ' (Qs. Al Isra`: 101). Maka beliau menjawab: \"Janganlah kalian menyekutukan Allah dengan sesuatu apapun, jangan membunuh jiwa yang diharamkan oleh Allah kecuali dengan hak, jangan mencuri, jangan berzina, jangan lari dari medan pertempuran, jangan melakukan sihir, jangan memakan riba, dan janganlah kalian menyerahkan orang yang tidak bersalah kepada penguasa hingga ia membunuhnya. Dan khusus bagi kalian hai orang-orang Yahudi! Janganlah kalian melanggar larangan (mencari ikan) pada hari sabtu.\" Maka kedua orang Yahudi itu pun berkata, \"Kami bersaksi bahwa anda adalah Rasulullah.\""},{"p":"Bukhari","n":122,"ar":"حَدَّثَنَا قَيْسُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا الْأَعْمَشُ سُلَيْمَانُ بْنُ مِهْرَانَ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَبَيْنَا أَنَا أَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خَرِبِ الْمَدِينَةِ وَهُوَ يَتَوَكَّأُ عَلَى عَسِيبٍ مَعَهُ فَمَرَّ بِنَفَرٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ لِبَعْضٍ سَلُوهُ عَنْ الرُّوحِ وَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ لَا يَجِيءُ فِيهِ بِشَيْءٍ تَكْرَهُونَهُ فَقَالَ بَعْضُهُمْ لَنَسْأَلَنَّهُ فَقَامَ رَجُلٌ مِنْهُمْ فَقَالَ يَا أَبَا الْقَاسِمِ مَا الرُّوحُ فَسَكَتَ فَقُلْتُ إِنَّهُ يُوحَى إِلَيْهِ فَقُمْتُ فَلَمَّا انْجَلَى عَنْهُ قَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي }وَمَا أُوتُوا مِنْ الْعِلْمِ إِلَّا قَلِيلًاقَالَ الْأَعْمَشُ هَكَذَا فِي قِرَاءَتِنَا","trj":"Telah menceritakan kepada kami [Qais bin Hafsh] berkata, telah menceritakan kepada kami ['Abdul Wahid] berkata, telah menceritakan kepada kami [Al A'masy Sulaiman bin Mihran] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] berkata, \"Ketika aku berjalan bersama Nabi shallallahu 'alaihi wasallam di sekitar pinggiran Kota Madinah, saat itu beliau membawa tongkat dari batang pohon kurma. Beliau lalu melewati sekumpulan orang Yahudi, maka sesama mereka saling berkata, \"Tanyakanlah kepadanya tentang ruh!\" Sebagian yang lain berkata, \"Janganlah kalian bicara dengannya hingga ia akan mengatakan sesuatu yang kalian tidak menyukainya.\" Lalu sebagian yang lain berkata, \"Sungguh, kami benar-benar akan bertanya kepadanya.\" Maka berdirilah seorang laki-laki dari mereka seraya bertanya, \"Wahai Abul Qasim, ruh itu apa?\" Beliau diam. Maka aku pun bergumam, \"Sesungguhnya beliau sedang menerima wahyu.\" Ketika orang itu berpaling, beliau pun membaca: '(Dan mereka bertanya kepadamu tentang ruh. Katakanlah: \"Ruh itu termasuk urusan Rabbku, dan tidaklah kamu diberi pengetahuan melainkan sedikit) ' (Qs. Al Israa`: 85). Al A'masy berkata, \"Seperti inilah dalam qira`ah kami.\""},{"p":"Bukhari","n":612,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَفْضُلُ صَلَاةُ الْجَمِيعِ صَلَاةَ أَحَدِكُمْ وَحْدَهُ بِخَمْسٍ وَعِشْرِينَ جُزْءًا وَتَجْتَمِعُ مَلَائِكَةُ اللَّيْلِ وَمَلَائِكَةُ النَّهَارِ فِي صَلَاةِ الْفَجْرِ ثُمَّ يَقُولُ أَبُو هُرَيْرَةَ فَاقْرَءُوا إِنْ شِئْتُمْ{ إِنَّ قُرْآنَ الْفَجْرِ كَانَ مَشْهُودًا }قَالَ شُعَيْبٌ وَحَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ تَفْضُلُهَا بِسَبْعٍ وَعِشْرِينَ دَرَجَةً","trj":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdurrahman] bahwa [Abu Hurairah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat berjama'ah lebih utama dibanding shalatnya salah seorang dari kalian dengan sendirian dengan dua puluh lima bagian. Dan Malaikat malam dan Malaikat siang berkumpul pada shalat fajar.\" Abu Hurairah kemudian berkata, \"Jika mau silahkan baca: '(Sesungguhnya shalat fajar disaksikan (oleh para Malaikat) ' (Qs. Al Israa: 78). [Syu'aib] berkata; telah menceritakan kepadaku [Nafi'] dari ['Abdullah bin 'Umar] ia berkata, \"(Shalat berjama'ah) dilebihkan dengan dua puluh tujuh derajat.\""},{"p":"Bukhari","n":2298,"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا ابْنُ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَحَوْلَ الْكَعْبَةِ ثَلَاثُ مِائَةٍ وَسِتُّونَ نُصُبًا فَجَعَلَ يَطْعُنُهَا بِعُودٍ فِي يَدِهِ وَجَعَلَ يَقُولُ{ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ }الْآيَةَ","trj":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ibnu Abi Najih] dari [Mujahid] dari [Abu Ma'mar] dari ['Abdullah bin Mas'ud radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam masuk ke Ka'bah saat yang ketika itu berisi tiga ratus enam puluh patung, lalu Beliau menusuk dan menghancurkannya dengan menggunakan tongkat yang ada di tangan Beliau seraya berkata: \"Telah datang kebenaran dan sirnalah kebathilan\", QS Al Isra' ayat 81."},{"p":"Bukhari","n":3409,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ أَوْ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى قَالَ سَلْ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ مَا أَمْرُهُمَا{ وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ لَمَّا أُنْزِلَتْ الَّتِي فِي الْفُرْقَانِ قَالَ مُشْرِكُو أَهْلِ مَكَّةَ فَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَقَدْ أَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ }الْآيَةَ فَهَذِهِ لِأُولَئِكَ وَأَمَّا الَّتِي فِي النِّسَاءِ الرَّجُلُ إِذَا عَرَفَ الْإِسْلَامَ وَشَرَائِعَهُ ثُمَّ قَتَلَ فَجَزَاؤُهُ جَهَنَّمُفَذَكَرْتُهُ لِمُجَاهِدٍ فَقَالَإِلَّا مَنْ نَدِمَ","trj":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] telah menceritakan kepadaku [Sa'id bin Jubair] -atau dia berkata, telah menceritakan kepadaku [Al Hakam] dari [Sa'id bin Jubair] berkata, - 'Abdurrahman bin Abza menyuruhku, katanya; \"Tanyalah kepada Ibnu 'Abbas tentang dua ayat ini dan apa maksudnya, yaitu yang pertama firman Allah dalam QS al Isra` ayat 33; (\"Dan janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan haq (alasan yang benar) \" dan yang kedua firman Allah dalam QS an Nisaa' ayat 93: (\"Dan barangsiapa yang membunuh orang beriman dengan sengaja...\"). Maka aku bertanya kepada [Ibnu 'Abbas], maka dia menjelaskan; Ketika turun firman Allah yang serupa ini pada surah al Furqan, orang-orang musyrik penduduk Makkah berkata; \"Sungguh kita telah membunuh jiwa yang diharamkan Allah dan kita juga menyembah selain Allah dan kita telah banyak berbuat maksiat, maka Allah menurunkan firman-Nya yang artinya: \"...kecuali siapa yang bertaubat dan beriman...\" (QS al Furqan ayat 70). Nah, ayat-ayat ini turun untuk mereka. Adapun ayat yang ada dalam surah an Nisaa' adalah bila seseorang telah mengenal Islam dan syari'atnya, kemudian dia membunuh seseorang dengan sengaja maka balasan baginya adalah neraka jahannam\". Kemudian keterangan ini aku sampaikan kepada Mujahidmaka dia berkata; \"Kecuali siapa yang menyesali perbuartannya\"."},{"p":"Bukhari","n":3442,"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَافِي قَوْلِهِ تَعَالَى{ وَمَا جَعَلْنَا الرُّؤْيَا الَّتِي أَرَيْنَاكَ إِلَّا فِتْنَةً لِلنَّاسِ }قَالَ هِيَ رُؤْيَا عَيْنٍ أُرِيَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ إِلَى بَيْتِ الْمَقْدِسِ قَالَ{ وَالشَّجَرَةَ الْمَلْعُونَةَ فِي الْقُرْآنِ }قَالَ هِيَ شَجَرَةُ الزَّقُّومِ","trj":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru] dari ['Ikrimah] dari [Ibnu 'Abbas] radliallahu 'anhuma tentang firman Allah Ta'ala QS al Isra' ayat 60: (\"Dan tidaklah kami jdikan mimpi yang Kami perlihatkann kepadamu melainkan sebagai ujian bagi manusia\"). Ibnu 'Abbas radliallahu 'anhuma berkata; \"Itu adalah penglihatan mata telanjang yang diperlihatkan kepada Rasulullah shallallahu 'alaihi wasallam pada malam beliau di Isra' menuju Baitul Maqdis\". Dan Ibnu 'Abbas radliallahu 'anhuma juga berkata; bahwa lanjutan ayat yang artinya: (\"dan begitu pula pohon yang terkutuk di dalam al Qur'an.\".) maksudnya adalah pohon zaqqum (di neraka) \"."},{"p":"Bukhari","n":3675,"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ يَوْمَ الْفَتْحِ وَحَوْلَ الْبَيْتِ سِتُّونَ وَثَلَاثُ مِائَةِ نُصُبٍ فَجَعَلَ يَطْعُنُهَا بِعُودٍ فِي يَدِهِ وَيَقُولُ{ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ }{ جَاءَ الْحَقُّ وَمَا يُبْدِئُ الْبَاطِلُ وَمَا يُعِيدُ }","trj":"Telah menceritakan kepada kami [Shadaqah bin Fadhl] Telah mengabarkan kepada kami [Ibnu 'Uyainah] dari [Ibnu Abu Najih] dari [Mujahid] dari [Abu Ma'mar] dari [Abdullah] radliallahu 'anhu, katanya, Nabi shallallahu 'alaihi wasallam memasuki Makkah pada penaklukan Makkah yang ketika itu di sekitar ka'bah ada tiga ratus enam puluh patung, lantas beliau porak-porandakan dengan sebongkah kayu di tangannya seraya beliau serukan \"Sekarang telah datang kebenaran dan kebatilan telah musnah.\" (QS. Isra'; 81), \"Sekarang kebenaran telah datang dan kebatilan tak akan terulang dan kembali lagi.\" (QS. Saba': 49)."},{"p":"Bukhari","n":4034,"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ قَالَ سَمِعْتُ ابْنَ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُقَالَ فِي بَنِي إِسْرَائِيلَ وَالْكَهْفِ وَمَرْيَمَ إِنَّهُنَّ مِنْ الْعِتَاقِ الْأُوَلِ وَهُنَّ مِنْ تِلَادِي{ فَسَيُنْغِضُونَ إِلَيْكَ رُءُوسَهُمْ }قَالَ ابْنُ عَبَّاسٍ يَهُزُّونَ وَقَالَ غَيْرُهُ نَغَضَتْ سِنُّكَ أَيْ تَحَرَّكَتْ","trj":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; Aku mendengar ['Abdur Rahman bin Yazid] dia berkata; Aku mendengar [Ibnu Mas'ud radliallahu 'anhu] dia berkata mengenai surat Bani Israil, Ashabul Al Kahfi, dan Maryam; Mereka adalah orang-orang terdahulu, dan surat-surat itu sudah lama aku membacanya. Adapun arti Lalu mereka akan menggeleng-gelengkan kepala mereka.. (Al Israa: 51). Ibnu Abbas berkata; yaitu menggerak-gerakannya. Yang lainnya berkata; 'Naghdlat Sinnuka.' Yakni; gigimu bergerak-gerak."},{"p":"Bukhari","n":4305,"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ بْنِ قَيْسٍ سَمِعْتُ ابْنَ مَسْعُودٍ يَقُولُفِي بَنِي إِسْرَائِيلَ وَالْكَهْفِ وَمَرْيَمَ وَطه وَالْأَنْبِيَاءِ إِنَّهُنَّ مِنْ الْعِتَاقِ الْأُوَلِ وَهُنَّ مِنْ تِلَادِي","trj":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata, Aku mendengar [Abdurrahman bin Yazid bin Qais] Aku mendengar [Ibnu Mas'ud] berkata terkait dengan surat Bani Isra`il, Al Kahfi Maryam, Thaaha dan Al Anbiya`, \"Sesungguhnya itu semua adalah dari surat-surat pertama yang diturunkan, dan semuanya pernah saya baca semenjak dahulu.\""},{"p":"Bukhari","n":5547,"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا مَالِكُ بْنُ سُعَيْرٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }أُنْزِلَتْ فِي الدُّعَاءِ","trj":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Malik bin Su'air] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] mengenai firman Allah; \"... Dan janganlah kamu mengeraskan suaramu dalam shalatmu dan janganlah pula merendahkannya...\" QS Al Isra`; 110. ayat ini di turunkan mengenai do'a."},{"p":"Bukhari","n":5798,"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ وَمَا جَعَلْنَا الرُّؤْيَا الَّتِي أَرَيْنَاكَ إِلَّا فِتْنَةً لِلنَّاسِ }قَالَ هِيَ رُؤْيَا عَيْنٍ أُرِيَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ إِلَى بَيْتِ الْمَقْدِسِ قَالَ{ وَالشَّجَرَةَ الْمَلْعُونَةَ فِي الْقُرْآنِ }قَالَ هِيَ شَجَرَةُ الزَّقُّومِ","trj":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Amru] dari [Ikrimah] dari [Ibnu 'Abbas] radliallahu 'anhuma, mengenai ayat; 'Dan tidaklah Kami jadikan mimpi yang Kami perlihatkan kepadamu selain sebagai cobaan bagi manusia', dia menuturkan; itu adalah mimpi sorotan mata jahat yang diperlihatkan kepada Rasulullah Shallallahu'alaihiwasallam ketika beliau diisra'kan ke baitul maqdis, dan dia mengatakan mengenai ayat; 'Dan pohon terlaknat dalam alquran' (QS. Al Isra-60), yaitu pohon zaqqum."},{"p":"Bukhari","n":6413,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرْثٍ بِالْمَدِينَةِ وَهُوَ يَتَوَكَّأُ عَلَى عَسِيبٍ فَمَرَّ بِنَفَرٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ سَلُوهُ عَنْ الرُّوحِ وَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ لَا يُسْمِعُكُمْ مَا تَكْرَهُونَ فَقَامُوا إِلَيْهِ فَقَالُوا يَا أَبَا الْقَاسِمِ حَدِّثْنَا عَنْ الرُّوحِ فَقَامَ سَاعَةً يَنْظُرُ فَعَرَفْتُ أَنَّهُ يُوحَى إِلَيْهِ فَتَأَخَّرْتُ عَنْهُ حَتَّى صَعِدَ الْوَحْيُ ثُمَّ قَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي }","trj":"Telah menceritakan kepada kami [Muhammad bin Ubaid bin Maimun] telah menceritakan kepada kami ['Isa bin Yunus] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Ibn Mas'ud] rahiyallahu'anhu berkata, \"Pernah aku bersama nabi shallallahu 'alaihi wasallam di sebuah kebun Madinah sedang beliau menyandarkan punggung, lantas beberapa orang Yahudi lewat, dan sebagian mereka mengatakan 'Coba tanyailah dia tentang roh! ' Sebagian berkata 'Jangan kalian tanyai dia tentang itu, sebab yang kalian benci tidak bisa memperdengarkan kepada kalian.' Namun sebagian mereka berdiri dan bertanya \"Wahai Abul Qasim, beritahukanlah kami tentang roh! ' Lantas beliau berdiri beberapa saat mengamat-amati, maka aku tahu bahwa beliau sedang menerima wahyu, maka aku berusaha menyingkir dari beliau, hingga wahyu terangkat, kemudian beliau bersabda mengutip ayat: '(Mereka bertanya kepadamu tentang roh, katakanlah bahwa roh itu urusan Rabbiku) ' (Qs. Al Israa`: 85)."},{"p":"Bukhari","n":6533,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقُلْنَا يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ قَالَ هَلْ تُضَارُونَ فِي رُؤْيَةِ الشَّمْسِ وَالْقَمَرِ إِذَا كَانَتْ صَحْوًا قُلْنَا لَا قَالَ فَإِنَّكُمْ لَا تُضَارُونَ فِي رُؤْيَةِ رَبِّكُمْ يَوْمَئِذٍ إِلَّا كَمَا تُضَارُونَ فِي رُؤْيَتِهِمَا ثُمَّ قَالَ يُنَادِي مُنَادٍ لِيَذْهَبْ كُلُّ قَوْمٍ إِلَى مَا كَانُوا يَعْبُدُونَ فَيَذْهَبُ أَصْحَابُ الصَّلِيبِ مَعَ صَلِيبِهِمْ وَأَصْحَابُ الْأَوْثَانِ مَعَ أَوْثَانِهِمْ وَأَصْحَابُ كُلِّ آلِهَةٍ مَعَ آلِهَتِهِمْ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ وَغُبَّرَاتٌ مِنْ أَهْلِ الْكِتَابِ ثُمَّ يُؤْتَى بِجَهَنَّمَ تُعْرَضُ كَأَنَّهَا سَرَابٌ فَيُقَالُ لِلْيَهُودِ مَا كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ عُزَيْرَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ قَالُوا نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ ثُمَّ يُقَالُ لِلنَّصَارَى مَا كُنْتُمْ تَعْبُدُونَ فَيَقُولُونَ كُنَّا نَعْبُدُ الْمَسِيحَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ فَيَقُولُونَ نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ فَيُقَالُ لَهُمْ مَا يَحْبِسُكُمْ وَقَدْ ذَهَبَ النَّاسُ فَيَقُولُونَ فَارَقْنَاهُمْ وَنَحْنُ أَحْوَجُ مِنَّا إِلَيْهِ الْيَوْمَ وَإِنَّا سَمِعْنَا مُنَادِيًا يُنَادِي لِيَلْحَقْ كُلُّ قَوْمٍ بِمَا كَانُوا يَعْبُدُونَ وَإِنَّمَا نَنْتَظِرُ رَبَّنَا قَالَ فَيَأْتِيهِمْ الْجَبَّارُ فِي صُورَةٍ غَيْرِ صُورَتِهِ الَّتِي رَأَوْهُ فِيهَا أَوَّلَ مَرَّةٍ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ أَنْتَ رَبُّنَا فَلَا يُكَلِّمُهُ إِلَّا الْأَنْبِيَاءُ فَيَقُولُ هَلْ بَيْنَكُمْ وَبَيْنَهُ آيَةٌ تَعْرِفُونَهُ فَيَقُولُونَ السَّاقُ فَيَكْشِفُ عَنْ سَاقِهِ فَيَسْجُدُ لَهُ كُلُّ مُؤْمِنٍ وَيَبْقَى مَنْ كَانَ يَسْجُدُ لِلَّهِ رِيَاءً وَسُمْعَةً فَيَذْهَبُ كَيْمَا يَسْجُدَ فَيَعُودُ ظَهْرُهُ طَبَقًا وَاحِدًا ثُمَّ يُؤْتَى بِالْجَسْرِ فَيُجْعَلُ بَيْنَ ظَهْرَيْ جَهَنَّمَ قُلْنَا يَا رَسُولَ اللَّهِ وَمَا الْجَسْرُ قَالَ مَدْحَضَةٌ مَزِلَّةٌ عَلَيْهِ خَطَاطِيفُ وَكَلَالِيبُ وَحَسَكَةٌ مُفَلْطَحَةٌ لَهَا شَوْكَةٌ عُقَيْفَاءُ تَكُونُ بِنَجْدٍ يُقَالُ لَهَا السَّعْدَانُ الْمُؤْمِنُ عَلَيْهَا كَالطَّرْفِ وَكَالْبَرْقِ وَكَالرِّيحِ وَكَأَجَاوِيدِ الْخَيْلِ وَالرِّكَابِ فَنَاجٍ مُسَلَّمٌ وَنَاجٍ مَخْدُوشٌ وَمَكْدُوسٌ فِي نَارِ جَهَنَّمَ حَتَّى يَمُرَّ آخِرُهُمْ يُسْحَبُ سَحْبًا فَمَا أَنْتُمْ بِأَشَدَّ لِي مُنَاشَدَةً فِي الْحَقِّ قَدْ تَبَيَّنَ لَكُمْ مِنْ الْمُؤْمِنِ يَوْمَئِذٍ لِلْجَبَّارِ وَإِذَا رَأَوْا أَنَّهُمْ قَدْ نَجَوْا فِي إِخْوَانِهِمْ يَقُولُونَ رَبَّنَا إِخْوَانُنَا كَانُوا يُصَلُّونَ مَعَنَا وَيَصُومُونَ مَعَنَا وَيَعْمَلُونَ مَعَنَا فَيَقُولُ اللَّهُ تَعَالَى اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ دِينَارٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ وَيُحَرِّمُ اللَّهُ صُوَرَهُمْ عَلَى النَّارِ فَيَأْتُونَهُمْ وَبَعْضُهُمْ قَدْ غَابَ فِي النَّارِ إِلَى قَدَمِهِ وَإِلَى أَنْصَافِ سَاقَيْهِ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ نِصْفِ دِينَارٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ ذَرَّةٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا قَالَ أَبُو سَعِيدٍ فَإِنْ لَمْ تُصَدِّقُونِي فَاقْرَءُوا{ إِنَّ اللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍ وَإِنْ تَكُ حَسَنَةً يُضَاعِفْهَا }فَيَشْفَعُ النَّبِيُّونَ وَالْمَلَائِكَةُ وَالْمُؤْمِنُونَ فَيَقُولُ الْجَبَّارُ بَقِيَتْ شَفَاعَتِي فَيَقْبِضُ قَبْضَةً مِنْ النَّارِ فَيُخْرِجُ أَقْوَامًا قَدْ امْتُحِشُوا فَيُلْقَوْنَ فِي نَهَرٍ بِأَفْوَاهِ الْجَنَّةِ يُقَالُ لَهُ مَاءُ الْحَيَاةِ فَيَنْبُتُونَ فِي حَافَتَيْهِ كَمَا تَنْبُتُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ قَدْ رَأَيْتُمُوهَا إِلَى جَانِبِ الصَّخْرَةِ وَإِلَى جَانِبِ الشَّجَرَةِ فَمَا كَانَ إِلَى الشَّمْسِ مِنْهَا كَانَ أَخْضَرَ وَمَا كَانَ مِنْهَا إِلَى الظِّلِّ كَانَ أَبْيَضَ فَيَخْرُجُونَ كَأَنَّهُمْ اللُّؤْلُؤُ فَيُجْعَلُ فِي رِقَابِهِمْ الْخَوَاتِيمُ فَيَدْخُلُونَ الْجَنَّةَ فَيَقُولُ أَهْلُ الْجَنَّةِ هَؤُلَاءِ عُتَقَاءُ الرَّحْمَنِ أَدْخَلَهُمْ الْجَنَّةَ بِغَيْرِ عَمَلٍ عَمِلُوهُ وَلَا خَيْرٍ قَدَّمُوهُ فَيُقَالُ لَهُمْ لَكُمْ مَا رَأَيْتُمْ وَمِثْلَهُ مَعَهُوَقَالَ حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُحْبَسُ الْمُؤْمِنُونَ يَوْمَ الْقِيَامَةِ حَتَّى يُهِمُّوا بِذَلِكَ فَيَقُولُونَ لَوْ اسْتَشْفَعْنَا إِلَى رَبِّنَا فَيُرِيحُنَا مِنْ مَكَانِنَا فَيَأْتُونَ آدَمَ فَيَقُولُونَ أَنْتَ آدَمُ أَبُو النَّاسِ خَلَقَكَ اللَّهُ بِيَدِهِ وَأَسْكَنَكَ جَنَّتَهُ وَأَسْجَدَ لَكَ مَلَائِكَتَهُ وَعَلَّمَكَ أَسْمَاءَ كُلِّ شَيْءٍ لِتَشْفَعْ لَنَا عِنْدَ رَبِّكَ حَتَّى يُرِيحَنَا مِنْ مَكَانِنَا هَذَا قَالَ فَيَقُولُ لَسْتُ هُنَاكُمْ قَالَ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ أَكْلَهُ مِنْ الشَّجَرَةِ وَقَدْ نُهِيَ عَنْهَا وَلَكِنْ ائْتُوا نُوحًا أَوَّلَ نَبِيٍّ بَعَثَهُ اللَّهُ إِلَى أَهْلِ الْأَرْضِ فَيَأْتُونَ نُوحًا فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ سُؤَالَهُ رَبَّهُ بِغَيْرِ عِلْمٍ وَلَكِنْ ائْتُوا إِبْرَاهِيمَ خَلِيلَ الرَّحْمَنِ قَالَ فَيَأْتُونَ إِبْرَاهِيمَ فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ ثَلَاث�� كَلِمَاتٍ كَذَبَهُنَّ وَلَكِنْ ائْتُوا مُوسَى عَبْدًا آتَاهُ اللَّهُ التَّوْرَاةَ وَكَلَّمَهُ وَقَرَّبَهُ نَجِيًّا قَالَ فَيَأْتُونَ مُوسَى فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ قَتْلَهُ النَّفْسَ وَلَكِنْ ائْتُوا عِيسَى عَبْدَ اللَّهِ وَرَسُولَهُ وَرُوحَ اللَّهِ وَكَلِمَتَهُ قَالَ فَيَأْتُونَ عِيسَى فَيَقُولُ لَسْتُ هُنَاكُمْ وَلَكِنْ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدًا غَفَرَ اللَّهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ فَيَأْتُونِي فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي فَيَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ أَيْضًا يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّانِيَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّالِثَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَهْ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَقَدْ سَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ حَتَّى مَا يَبْقَى فِي النَّارِ إِلَّا مَنْ حَبَسَهُ الْقُرْآنُ أَيْ وَجَبَ عَلَيْهِ الْخُلُودُ قَالَ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ عَسَى أَنْ يَبْعَثَكَ رَبُّكَ مَقَامًا مَحْمُودًا }قَالَ وَهَذَا الْمَقَامُ الْمَحْمُودُ الَّذِي وُعِدَهُ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Allaits bin Sa'd] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Zaid] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudzri] berkata, \"Kami bertanya, \"Ya Rasulullah, apakah kita akan melihat Tuhan kita pada hari kiamat?\" Nabi balik bertanya: \"Apakah kalian merasa kesulitan melihat matahari dan bulan ketika terang benderang?\" kami menjawab, \"Tidak.\" Nabi meneruskan: \"Begitulah kalian tidak kesulitan melihat melihat Tuhan kalian ketika itu, selain sebagaimana kesulitan kalian melihat keduanya.\" Kemudian beliau berkata: \"Lantas ada seorang penyeru memanggil-manggil, \"Hendaklah setiap kaum pergi menemui yang disembahnya!\" Maka pemuja salib pergi bersama salib mereka, dan pemuja patung menemui patung-patung mereka, dan setiap pemuja Tuhan bersama tuhan-tuhan mereka hingga tinggal orang-orang yang menyembah Allah, entah baik atau durhaka dan ahli kitab terdahulu. Kemudian jahannam didatangkan dan dipasang, ia seolah-olah fatamorgana, lantas orang-orang yahudi ditanya, \"Apa yang dahulu kalian sembah?\" Mereka menjawab, \"Kami dahulu menyembah Uzair anak Allah.\" Lalu ada suara, \"Kalian dusta! Allah sama sekali tidak mempunyai isteri dan tidak pula anak.\" Lalu apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin jika Engkau memberi kami minuman!\" Lantas ada suara, \"Minumlah kalian!\" Lalu mereka berjatuhan di neraka jahannam. Lantas orang-orang Nashara diseru, \"Apa yang kalian dahulu sembah?\" Mereka menjawab, \"Kami dahulu menyembah Isa al Masih, anak Anak Allah.\" Mereka dijawab, \"Kamu semua bohong! Allah sama sekali tidak mempunyai isteri atau bahkan anak, dan apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin agar Engkau memberi kami minuman!\" Lalu dijawab, \"Minumlah kalian!\" Dan langsung mereka berjatuhan di neraka jahannam hingga tersisa manusia yang menyembah Allah, entah yang baik atau berbuat durhaka. Mereka ditanya, \"Apa yang menyebabkan kalian tertahan padahal manusia lainnya sudah pergi?\" Mereka menjawab, \"Kami memisahkan diri dari mereka dan kami adalah manusia yang paling membutuhkan-Nya, kami dengar ada seorang juru seru menyerukan diri, \"Hendaklah setiap kaum menemui yang mereka sembah! Hanyasanya kami menunggu-nunggu Tuhan kami.\" Beliau melanjutkan, \"Lantas Allah (Al jabbar) mendatangi mereka dengan bentuk yang belum pernah mereka lihat pertama kali, lalu Allah firmankan: 'Akulah Tuhan kalian.' Mereka menjawab, 'Engkau adalah rabb kami, dan tidak ada yang berani mengajak-Nya bicara selain para nabi shallallahu 'alaihi wasallam, lantas para nabi berkata, 'Bukankah di antara kalian dan Allah ada tanda yang kalian mengenalnya? ' Mereka menjawab, 'Ya, yaitu betis, ' maka Allah pun menyingkap betis-Nya sehingga setiap mukmin bersujud kepada-Nya. Lalu tersisalah orang-orang yang sujud kepada Allah karena riya dan sum'ah sehingga ia pergi sujud dan punggungnya kembali menjadi satu bagian, kemudian titian (jembatan) jahannam didatangkan dan dipasang antara dua tepi jahannam, kami bertanya, 'Wahai Rasulullah, memang jembatan jahannam tersebut misterinya apa? ' Nabi menjawab: 'Jembatan itu bisa menggelincirkan, menjatuhkan, ada pengait-pengait besi, ada duri-duri yang lebar dan tajam, durinya besok yang terbuat dari kayu berduri namanya Sa'dan (kayu berduri tajam). Orang mukmin yang melewatinya sedemikian cepat, ada yang bagaikan kedipan mata, ada yang bagaikan kilat, ada yang bagaikan angin, dan ada yang bagaikan kuda pilihan. Ada yang bagaikan kuda tunggangan, ada yang selamat dengan betul-betul terselamatkan, namun ada juga yang selamat setelah tercabik-cabik oleh besi-besi pengait itu, atau terlempar karenanya di neraka jahannam, hingga manusia terakhir kali melewati dengan diseret seret, dan kalian tidak bisa sedemikian gigihnya menyumpahiku terhadap kebenaran yang jelas bagi kalian daripada terhadap seorang mukmin ketika itu kepada Allah Al Jabbar. Jika mereka melihat bahwasanya mereka telah selamat di kalangan teman-teman mereka, mereka berkata, 'Ya Tuhan kami, sesungguhnya kawan-kawan kami mendirikn shalat bersama kami dan berpuasa bersama kami, dan beramal bersama kami! ' Allah Ta'ala berfirman, 'Pergilah kalian, siapa diantara kalian dapatkan dalam hatinya masih ada seberat dinar keimanan, maka keluarkanlah dia', dan Allah mengharamkan bentuk mereka dalam neraka. Maka mereka datangi kawan-kawan mereka sedang sebagian mereka telah terendam dalam neraka ada yang sampai telapak kakinya, setengah betisnya, sehingga mereka keluarkan siapa saja yang mereka, kemudian mereka kembali dan Allah berkata, 'Pergilah kalian sekali lagi, dan siapa yang kalian temukan dalam hatinya seberat atom keimanan, maka keluarkanlah dia.' Maka mereka keluarkan siapa saja yang mereka kenal.\" Rasulullah berkata: 'Jika kalian tidak mempercayaiku, maka bacalah: '(Allah tidak menzhalimi seberat biji sawi pun, jika ada kebaikan, maka Allah melipatgandakan balasannya) ' (Qs. An nisaa': 40), maka para nabi shallallahu 'alaihi wasallam, malaikat dan orang-orang yang beriman, kesemuanya memberi syafaat. Kemudian Allah Al Jabbar berkata, syafaat-Ku masih ada. Lantas Allah menggenggam segenggam dari neraka dan mengentaskan beberapa kaum yang mereka telah terbakar, lantas mereka dilempar ke sebuah sungai di pintu surga yang namanya 'Sungai kehidupan' sehingga mereka tumbuh dalam kedua tepinya sebagaimana biji-bijian tumbuh dalam genangan sungai yang kalian sering melihatnya di samping batu karang dan samping pohon, apa yang diantaranya condong kepada matahari, maka berwarna hijau, dan apa yang diantaranya condong kepada bayangan, maka berwarna putih, lantas mereka muncul seolah-olah mutiara dan dalam tengkuk mereka terdapat cincin-cincin. Mereka kemudian masuk surga hingga penghuni surga berkata, 'Mereka adalah 'utaqa' Ar Rahman (orang-orang yang dibebaskan Arrahman), Allah memasukkan mereka bukan karena amal yang mereka lakukan, dan bukan pula karena kebaikan yang mereka persembahkan sehingga mereka memperoleh jawaban 'Bagimu yang kau lihat dan semisalnya'.\" [Hajjaj bin Minhal] berkata; telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dari [Anas] radliyallahu'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: 'Pada hari kiamat nanti orang-orang mukmin ditahan hingga yang demikian menjadikan mereka sedih. Mereka katakan, 'Duh, sekiranya kita meminta syafaat kepada Tuhan kami sehingga Dia menjadikan kita merasa nyaman dari tempat kita ini.' Mereka pun mendatangi Adam dan berkata, 'Engkau hai Adam, Engkau adalah nenek moyang seluruh manusia, Allah menciptamu dengan tangan-Nya, menjadikan surga sebagai tempat hunianmu dan menjadikan malaikat bertunduk sujud kepadamu, Allah juga mengajarimu nama-nama segala sesuatu agar engkau bisa memberi syafaat kepada kami disisi Tuhanmu sehingga engkau bisa memberi kenyamanan di tempat kami ini. Namun Adam hanya menjawab, 'Disini saya tak berhak memberi syafaat untuk kalian'.\" Rasulullah melanjutkan: \"Lantas Adam mengingatkan kesalahan yang pernah dilakukannya, yaitu memakan pohon larangan padahal telah dilarang, dan ia katakan 'Coba kalian datangi Nuh, sebab ia adalah nabi shallallahu 'alaihi wasallam pertama-tama yang Allah utus kepada penduduk bumi.' Mereka pun mendatangi Nuh, namun Nuh juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', dan Nuh menyebutkan kesalahan yang pernah dilakukannya, yaitu bertanya kepada Rabbnya dengan tanpa ilmu sambil ia katakan, 'Cobalah kalian datangi Ibrahim, sebab ia adalah Khalilurrahman (kekasih Arrahman).\" Rasulullah melanjutkan lagi kisahnya: \"Mereka pun mendatangi Ibrahim, hanya Ibrahim juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', Ibrahim lantas menyebutkan kesalahannya, yaitu tiga kebohongan yang pernah dilakukannya sambil berkata, 'Cobalah kalian datangi Musa, seorang hamba yang Allah memberinya taurat, mengajaknya bicara dan mendekatkannya kepada-Nya sedekat-dekatnya'.\" Rasulullah lanjutkan: \"Mereka pun mendatangi Musa, hanya Musa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil Musa mengingatkan kesalahan yang pernah dilakukannya, yaitu membunuh jiwa tanpa alasan yang dibenarkan, sambil ia katakan, 'Coba kalian datangi Isa, seorang hamba Allah dan rasul-Nya, ruh Allah dan kalimah-Nya. Merekapun mendatangi Isa, namun 'Isa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil ia katakan 'Cobalah kalian datangi Muhammad Shallallahu'alaihiwasallam, seorang hamba yang Allah telah mengampuni dosanya yang terdahulu dan yang akan datang.' Lantas mereka mendatangi aku (Muhammad) dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud, Allah lalu membiarkan aku sekehendak Dia membiarkaku. Allah lantas berkata, 'Angkat kepalamu hai Muhammad, katakanlah, engkau didengar, mintailah syafaat, engkau diberi syafaat, mintalah, engkau diberi.' Aku lalu angkat kepalaku dan aku memuji Tuhanku dengan pujian yang Ia ajarkannya kepadaku, kemudian aku memberi syafaat dan Dia memberiku batasan. Kemudian aku keluar dan memasukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku juga mendengarnya menyebutkan, \"Aku lalu keluar, kemudian aku keluarkan mereka dari neraka dan kumasukkan ke dalam surga. Setelah itu aku kembali untuk kali kedua dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan untuk menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud. Allah lantas membiarkanku sekehendak Allah membiarkan, kemudian Allah berkata, 'Angkatlah kepalamu hai Muhammad dan katakanlah engkau akan didengar, dan berilah syafaat engkau akan diberi syafaat, dan mintalah engkau akan diberi.' Aku lalu angkat kepalaku dan memanjatkan pujian dan pujaan terhadap tuhanku sebagaimana yang diajakrkan-Nya kepadaku. Kemudian aku memberi syafaat, dan Ia memberiku batasan sehingga aku keluar dan aku masukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, \"Dan aku berangkat sehingga aku keluarkan mereka dari neraka, lalu mereka aku masukkan ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, 'Maka aku berangkat dan aku keluarkan mereka dari neraka, untuk kemudian aku masukkan mereka ke dalam surga, hingga tidak tersisa dalam neraka selain yang digi ditahan oleh alquran, atau maksudnya ia wajib abadi, kemudian beliau membaca ayat ini '(semoga Tuhanmu membangkitkankmu di tempat yang terpuji) ' (Qs. Al Isra': 79). Nabi mengatakan, \"Inilah maqam terpuji yang dijanjikan untuk nabi shallallahu 'alaihi wasallam kalian.\""},{"p":"Bukhari","n":6547,"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَكُنْتُ أَمْشِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرْثٍ بِالْمَدِينَةِ وَهُوَ مُتَّكِئٌ عَلَى عَسِيبٍ فَمَرَّ بِقَوْمٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ لِبَعْضٍ سَلُوهُ عَنْ الرُّوحِ وَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ عَنْ الرُّوحِ فَسَأَلُوهُ فَقَامَ مُتَوَكِّئًا عَلَى الْعَسِيبِ وَأَنَا خَلْفَهُ فَظَنَنْتُ أَنَّهُ يُوحَى إِلَيْهِ فَقَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي وَمَا أُوتِيتُمْ مِنْ الْعِلْمِ إِلَّا قَلِيلًا }فَقَالَ بَعْضُهُمْ لِبَعْضٍ قَدْ قُلْنَا لَكُمْ لَا تَسْأَلُوهُ","trj":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] berkata, \"Pernah aku berjalan bersama Rasulullah shallallahu 'alaihi wasallam di sebuah kebun di Madinah, saat beliau bertelekan di atas tongkat. Kemudian beliau melewati sekelompok orang Yahudi, sebagian diantara mereka bertanya kepada sebagian lainnya 'Coba tanyailah dia tentang nyawa', sedang sebagian lain berkata 'Jangan tanyai dia tentang nyawa'. Kemudian beliau berdiri bertelekan di atas tongkatnya sedang saya berada di belakangnya, aku taksir beliau sedang menerima wahyu, lantas beliau membacakan kepada mereka: '(Dan mereka bertanya kepadamu tentang nyawa, katakanlah bahwa nyawa itu adalah urusan tuhanku, dan tidaklah kamu diberi ilmu melainkan sedikit) ' (Qs. Al Isra': 85). Maka sebagian di antara mereka berkata kepada sebagian lainnya, 'Kan telah kami katakan kepada kalian, jangan kalian tanya tentangnya! '"},{"p":"Bukhari","n":6553,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ عَنْ عَبْدِ الْوَاحِدِ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ ابْنِ مَسْعُودٍ قَالَبَيْنَا أَنَا أَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ حَرْثِ الْمَدِينَةِ وَهُوَ يَتَوَكَّأُ عَلَى عَسِيبٍ مَعَهُ فَمَرَرْنَا عَلَى نَفَرٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ لِبَعْضٍ سَلُوهُ عَنْ الرُّوحِ فَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ أَنْ يَجِيءَ فِيهِ بِشَيْءٍ تَكْرَهُونَهُ فَقَالَ بَعْضُهُمْ لَنَسْأَلَنَّهُ فَقَامَ إِلَيْهِ رَجُلٌ مِنْهُمْ فَقَالَ يَا أَبَا الْقَاسِمِ مَا الرُّوحُ فَسَكَتَ عَنْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلِمْتُ أَنَّهُ يُوحَى إِلَيْهِ فَقَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي }وَمَا أُوتُوا مِنْ الْعِلْمِ إِلَّا قَلِيلًاقَالَ الْأَعْمَشُ هَكَذَا فِي قِرَاءَتِنَا","trj":"Telah menceritakan kepada kami [Musa bin Ismail] dari [Abdul Wahid] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Ibnu Mas'ud] berkata, \"Pernah aku berjalan bersama nabi shallallahu 'alaihi wasallam di sebagian kebun Madinah, sedang ketika itu beliau bersandar di atas sebuah dahan pohon kurma, saat kami melewati beberapa orang Yahudi, sebagian mereka berkata kepada sebagian lainnya, 'Tolong tanyailah dia (Muhammad) tentang nyawa', sementara sebagian mereka berkata, 'Jangan engkau bertanya kepadanya suatu hal yang kalian sendiri ketakutan terhadapnya'. Namun sebagian mereka ngotot berkata, 'Sungguh kami akan bertanya kepadanya! ' Lalu sebagian di antara mereka datang menemui beliau dan berkata, \"Wahai abu Qasim, apa nyawa itu?\" Nabi shallallhu'lihiwasallam terdiam, maka aku pun tahu bahwa beliau sedang menerima wahyu. Lantas beliau membacakan ayat: '(Dan mereka bertanya kepadamu tentang nyawa, katakanlah 'Bahwasanya nyawa itu urusan Tuhanku, dan tidaklah kalian diberi ilmu kecuali sedikit saja) ' (Qs. Al Isra': 85)."},{"p":"Bukhari","n":6574,"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ هُشَيْمٍ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }قَالَ أُنْزِلَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَوَارٍ بِمَكَّةَ فَكَانَ إِذَا رَفَعَ صَوْتَهُ سَمِعَ الْمُشْرِكُونَ فَسَبُّوا الْقُرْآنَ وَمَنْ أَنْزَلَهُ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ تَعَالَى{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }{ لَا تَجْهَرْ بِصَلَاتِكَ }حَتَّى يَسْمَعَ الْمُشْرِكُونَ{ وَلَا تُخَافِتْ بِهَا }عَنْ أَصْحَابِكَ فَلَا تُسْمِعُهُمْ{ وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }أَسْمِعْهُمْ وَلَا تَجْهَرْ حَتَّى يَأْخُذُوا عَنْكَ الْقُرْآنَ","trj":"Telah menceritakan kepada kami [Musaddad] dari [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibn Abbas] mengenai ayat: '(Dan janganlah engkau mengeraskan bacaan shalatmu dan jangan pula engkau merendahkan bacaannya) ' (Qs. Al Isra': 110), ayat ini diturunkan kepada Rasulullah shallallahu 'alaihi wasallam secara berturut-turut di Makkah. Ketika itu, jika beliau mengencangkan bacaannya, maka kaum musyrikin mendengarnya hingga mereka mencela Al Qur'an secara habis-habisan, juga mencela yang menurunkannya dan yang membawanya. Maka Allah menurunkan: '(Jangan kamu mengeraskan bacaan shalatmu dan jangan pula merendahkannya) ' (Qs. Al Isra': 110). Jangan kamu mengeraskan bacaanmu maksudnya hingga terdengar oleh orang-orang musyrik, dan jangan pula kamu merendahkannya, maksudnya sehingga tidak terdengar oleh kawan-kawanmu. Dan carilah jalan tengah di antara keduanya, maksudnya bacalah sehingga terdengar oleh kawanmu namun jangan pula kamu membaca terlalu keras hingga musuh mencela Al Qur'an akibat bacaanmu.\""},{"p":"Bukhari","n":6601,"ar":"حَدَّثَنِي عَمْرُو بْنُ زُرَارَةَ عَنْ هُشَيْمٍ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَافِي قَوْلِهِ تَعَالَى{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }قَالَ نَزَلَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُخْتَفٍ بِمَكَّةَ فَكَانَ إِذَا صَلَّى بِأَصْحَابِهِ رَفَعَ صَوْتَهُ بِالْقُرْآنِ فَإِذَا سَمِعَهُ الْمُشْرِكُونَ سَبُّوا الْقُرْآنَ وَمَنْ أَنْزَلَهُ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ }أَيْ بِقِرَاءَتِكَ فَيَسْمَعَ الْمُشْرِكُونَ فَيَسُبُّوا الْقُرْآنَ{ وَلَا تُخَافِتْ بِهَا }عَنْ أَصْحَابِكَ فَلَا تُسْمِعُهُمْ{ وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }","trj":"Telah menceritakan kepadaku ['Amru bin Zurarah] dari [Husyaim] telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibn Abbas] radliyallahu'anhuma tentang firman Allah Ta'ala: '(Jangan kamu membacanya secara lantang dalam shalatmu, dan jangan pula secara lirih) ' (Qs. Al Isra': ayat 110), Ibn Abbas berkata, \"Ayat ini diturunkan saat Rasulullah shallallahu 'alaihi wasallam masih sembunyi-sembunyi di Makkah, jika shalat bersama sahabat-sahabatnya, beliau mengeraskan bacaan Al Qur'annya, sehingga jika kaum musyrikin mendengarnya, mereka mencaci Al Qur'an, Dzat yang menurunkannya dan malaikat yang membawanya. Maka Allah menegur nabi-Nya shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam dengan ayat: '(Jangan kamu membacanya secara lantang dalam shalatmu) ' (Qs. Al Isra': ayat 110), yakni dengan bacaanmu, sehingga saat orang-orang Musyrik mendengar mereka akan mencela Al Qur'an, '(dan jangan pula secara lirih), yaitu kepada para sahabatmu, sehingga engkau tidak bisa menjadikan mereka mendengar, (Carilah jalan tengah antara keduanya) ', (Qs. Al Isra: ayat 110)."},{"p":"Bukhari","n":6602,"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْنَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }فِي الدُّعَاءِ","trj":"Telah menceritakan kepada kami [Ubaid bin Ismail] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Ayahnya] dari [Aisyah] radliyallahu'anha, ia berkata, \"Ayat ini: '(Janganlah kamu menyaringkan bacaanmu ketika shalatmu dan jangan pula membacanya terlalu lirih) ', (Qs. Al Isra`: Ayat 110), diturunkan berkenaan dengan doa.\""},{"p":"Bukhari","n":6622,"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَوَارِيًا بِمَكَّةَ وَكَانَ يَرْفَعُ صَوْتَهُ فَإِذَا سَمِعَ الْمُشْرِكُونَ سَبُّوا الْقُرْآنَ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ عَزَّ وَجَلَّ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }","trj":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibn 'Abbas] radliyallahu'anhuma, ia berkata, \"Nabi Shallalahu'alaihiwasllam sembunyi-sembunyi di Makkah, namun beliau mengeraskan suara bacaan, saat orang-orang musyrik mendengar (suara bacaan beliau), mereka mencaci Al Qur'an dan orang yang membawanya. Maka Allah Azza wa Jalla pun menurunkan ayat kepada nabi-Nya: '(Dan janganlah engkau menyaringkan bacaan shalatmu dan jangan pula melirihkannya) ', (Qs. Al Isra': 110)."},{"p":"Darimi","n":212,"ar":" أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ أَبِي أُسَامَةَ عَنْ مِسْعَرٍ قَالَ سَمِعْتُ عَبْدَ الْأَعْلَى التَّيْمِيَّ يَقُولُ مَنْ أُوتِيَ مِنْ الْعِلْمِ مَا لَا يُبْكِيهِ لَخَلِيقٌ أَنْ لَا يَكُونَ أُوتِيَ عِلْمًا يَنْفَعُهُ لِأَنَّ اللَّهَ تَعَالَى نَعَتَ الْعُلَمَاءَ ثُمَّ قَرَأَ الْقُرْآنَ { إِنَّ الَّذِينَ أُوتُوا الْعِلْمَ إِلَى قَوْلِهِ يَبْكُونَ }","trj":"Telah mengabarkan kepada kami [Sa'id bin Sulaiman] dari [Abu Usamah] dari [Mis'ar] ia berkata: \"Aku pernah mendengar [Abdul A'la At Taimi] berkata: 'Barangsiapa yang dianugerahi ilmu dan ilmunya tidak membuatnya menangis kepada Allah, berarti ia mendapatkan ilmu yang tidak bermanfaat, karena Allah mensifati para ulama, kemudian ia membaca Al Qur`an: INNALLADZIINA UUTUL 'ILMA\" (sesungguhnya orang-orang yang dianugerahi ilmu) sampai firmanNya: \"YABKUUN\" (mereka selalu menangis) -Qs. Al Isra`: 107-108-' \"."},{"p":"Darimi","n":1927,"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ إِيَادٍ حَدَّثَنَا إِيَادٌ عَنْ أَبِي رِمْثَةَ قَالَ انْطَلَقْتُ مَعَ أَبِي نَحْوَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِأَبِي ابْنُكَ هَذَا فَقَالَ إِي وَرَبِّ الْكَعْبَةِ قَالَ حَقًّا قَالَ أَشْهَدُ بِهِ قَالَ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَاحِكًا مِنْ ثَبَتِ شَبَهِي فِي أَبِي وَمِنْ حَلِفِ أَبِي عَلَيَّ فَقَالَ إِنَّ ابْنَكَ هَذَا لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِ قَالَ وَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }","trj":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami ['Ubaidullah bin Iyad] telah menceritakan kepada kami [Iyad] dari [Abu Rimtsah], ia berkata; aku pergi bersama ayahku menemui Rasulullah shallallahu 'alaihi wasallam, kemudian beliau bersabda kepada ayahku: \"Apakah ini anakmu?\" Ayahku menjawab; \"Ya, demi Rabb Pemilik Ka'bah.\" Beliau bersabda: \"Apakah benar (ini anakmu)?\" Ayahku menjawab; \"Aku bersaksi dengannya.\" Abu Rimtsah berkata; Kemudian Rasulullah shallallahu 'alaihi wasallam tersenyum karena kemiripanku dengan ayahku dan karena sumpah ayahku atas diriku. Beliau lalu bersabda: \"Sesungguhnya anakmu ini tidak dihukum karena kejahatanmu dan engkau tidak dihukum karena kejahatannya.\" Abu Rimtsah berkata; Rasulullah shallallahu 'alaihi wasallam lalu membaca ayat: \" Dan seorang yang berdosa tidak akan memikul dosa orang lain.\" QS Al Isra`; 15."},{"p":"Malik","n":452,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَإِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }فِي الدُّعَاءِ","trj":"Telah menceritakan kepadaku dari Malik dari [Hisyam bin Urwah] dari [Bapaknya] bahwa dia berkata, \"Diturunkannya ayat ini: '(dan janganlah kamu mengeraskan suaramu dalam shalatmu dan janganlah pula merendahkannya dan carilah jalan tengah di antara kedua itu) ' (Qs. Al Israa`: 110) berkenaan dengan masalah doa.\""},{"p":"Muslim","n":1002,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَفْضُلُ صَلَاةٌ فِي الْجَمِيعِ عَلَى صَلَاةِ الرَّجُلِ وَحْدَهُ خَمْسًا وَعِشْرِينَ دَرَجَةً قَالَ وَتَجْتَمِعُ مَلَائِكَةُ اللَّيْلِ وَمَلَائِكَةُ النَّهَارِ فِي صَلَاةِ الْفَجْرِقَالَ أَبُو هُرَيْرَةَ اقْرَءُوا إِنْ شِئْتُمْ{ وَقُرْآنَ الْفَجْرِ إِنَّ قُرْآنَ الْفَجْرِ كَانَ مَشْهُودًا }و حَدَّثَنِي أَبُو بَكْرِ بْنُ إِسْحَقَ حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدٌ وَأَبُو سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِمِثْلِ حَدِيثِ عَبْدِ الْأَعْلَى عَنْ مَعْمَرٍ إِلَّا أَنَّهُ قَالَ بِخَمْسٍ وَعِشْرِينَ جُزْءًا","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat secara berjamaah lebih utama dua puluh lima derajat daripada shalat secara individual, \" Beliau melanjutkan: \"Dan para malaikat malam dan malaikat siang berkumpul ketika shalat fajar (subuh).\" Abu Hurairah; \"jika kalian berkenan, maka bacalah \"Dan tunaikanlah bacaan fajar (subuh) sesungguhnya bacaan (shalat subuh) disaksikan oleh para malaikat.\" QS. Al-Isra\"; 78. Dan telah menceritakan kepadaku [Abu Bakr bin Ishaq] telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] katanya; telah mengabarkan kepadaku [Said] dan [Abu Salamah], bahwa [Abu Hurairah] berkata; \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda seperti hadis Abdul A'la dari Ma'mar, hanya ia mengatakan dengan redaksi \"Lebih utama dua puluh lima bagian.\""},{"p":"Muslim","n":3100,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ وَابْنُ أَبِي عُمَرَ وَاللَّفْظُ لِابْنِ أَبِي شَيْبَةَ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَحَوْلَ الْكَعْبَةِ ثَلَاثُ مِائَةٍ وَسِتُّونَ نُصُبًا فَجَعَلَ يَطْعُنُهَا بِعُودٍ كَانَ بِيَدِهِ وَيَقُولُ{ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ إِنَّ الْبَاطِلَ كَانَ زَهُوقًا }{ جَاءَ الْحَقُّ وَمَا يُبْدِئُ الْبَاطِلُ وَمَا يُعِيدُ }زَادَ ابْنُ أَبِي عُمَرَ يَوْمَ الْفَتْحِو حَدَّثَنَاه حَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ كِلَاهُمَا عَنْ عَبْدِ الرَّزَّاقِ أَخْبَرَنَا الثَّوْرِيُّ عَنْ ابْنِ أَبِي نَجِيحٍ بِهَذَا الْإِسْنَادِ إِلَى قَوْلِهِ زَهُوقًا وَلَمْ يَذْكُرْ الْآيَةَ الْأُخْرَى وَقَالَ بَدَلَ نُصُبًا صَنَمًا","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan ['Amru An Naqid] serta [Ibnu Abu Umar] sedangkan lafadznya dari Ibnu Abu Syaibah, mereka berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ibnu Abu Najih] dari [Mujahid] dari [Abu Ma'mar] dari [Abdullah] dia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam masuk Makkah, saat itu terdapat tiga ratus enam puluh patung di sekitar Ka'bah. Lantas dengan tongkatnya beliau memukul patung tersebut sambil membaca: \"Telah datang kebenaran dan lenyaplah kebatilan, sesungguhnya kebatilan pasti lenyap…) ' (Qs. Al Israa: 81) '(Kebenaran telah datang dan yang batil itu tidak akan memulai dan tidak (pula) akan mengulangi) ' (Qs. Sabaa: 49). Ibnu Abu Umar menambahkan, \"Ketika hari penaklukan Kota Makkah.\" Dan telah menceritakan kepada kami [Hasan bin Ali Al Khulwani] dan [Abd bin Humaid] keduanya dari [Abdurrazaq] telah mengabarkan kepada kami [At Tsauri] dari [Ibnu Abu Najih] dengan isnad ini hingga perkataan, \"(dan kebatilan) itu pasti lenyap.\" Dan tidak menyebutkan ayat yang lain, dia juga berkata, \"Arca\" sebagai ganti dari \"Patung.\""},{"p":"Nasa'i","n":999,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مَنِيعٍ وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ قَالَا حَدَّثَنَا هُشَيْمٌ قَالَ حَدَّثَنَا أَبُو بِشْرٍ جَعْفَرُ بْنُ أَبِي وَحْشِيَّةَ وَهُوَ ابْنُ إِيَاسٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }قَالَ نَزَلَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُخْتَفٍ بِمَكَّةَ فَكَانَ إِذَا صَلَّى بِأَصْحَابِهِ رَفَعَ صَوْتَهُ وَقَالَ ابْنُ مَنِيعٍ يَجْهَرُ بِالْقُرْآنِ وَكَانَ الْمُشْرِكُونَ إِذَا سَمِعُوا صَوْتَهُ سَبُّوا الْقُرْآنَ وَمَنْ أَنْزَلَهُ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ عَزَّ وَجَلَّ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ }أَيْ بِقِرَاءَتِكَ فَيَسْمَعَ الْمُشْرِكُونَ فَيَسُبُّوا الْقُرْآنَ{ وَلَا تُخَافِتْ بِهَا }عَنْ أَصْحَابِكَ فَلَا يَسْمَعُوا{ وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }","trj":"Telah mengabarkan kepada kami [Ahmad bin Mani'] dan [Ya'qub bin Ibrahim Ad-Dauraqiy] mereka berdua berkata; telah menceritakan kepada kami [Husyaim] dia berkata; telah menceritakan kepada kami [Abu Bisyr Ja'far bin Abu Wahsyiyyah bin Iyas] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] tentang firman Allah Azza wa Jalla, \"Janganlah kamu mengeraskan suaramu dalam shalatmu dan Janganlah pula merendahkannya.\" (Qs. Al Israa' (17): 1 10), dia berkata; \"Ayat ini turun dan Rasulullah Shallallahu'alaihi wasallam masih sembunyi-sembunyi dalam berdakwah di Makkah. Jika beliau mengerjakan shalat dengan para sahabatnya, maka beliau Shallallahu'alaihi wasallam mengeraskan suaranya, Ibnu Mani' berkata, \"Beliau memperdengarkan bacaan Al Qur'annya. Adalah orang-orang musyrik yang mendengar suara Rasulullah Shallallahu'alaihi wasallam (saat membaca Al Qur'an) mencela Al Qur'an, yang menurunkannya (Allah), serta yang membawanya (malaikat Jibril). Oleh karena itu Allah Azza wa Jalla berfirman kepada nabi-Nya, \"Janganlah kamu mengeraskan suaramu dalam shalatmu\" yakni dalam bacaannya. -Jika- Orang musyrik mendengar hal ini, maka mereka mencela Al Qur'an.\"Dan janganlah pula melirihkannya\" dari sahabatmu hingga mereka tidak mendengar.\"Dan carilah jalannya diantara keadaan yang demikian.\" (Qs. Al Israa' (17): 110)."},{"p":"Nasa'i","n":3509,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ قَالَ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ عَطَاءٍ وَهُوَ ابْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَقْرَبُوا مَالَ الْيَتِيمِ إِلَّا بِالَّتِي هِيَ أَحْسَنُ }وَ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ اجْتَنَبَ النَّاسُ مَالَ الْيَتِيمِ وَطَعَامَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَشَكَوْا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَيَسْأَلُونَكَ عَنْ الْيَتَامَى قُلْ إِصْلَاحٌ لَهُمْ خَيْرٌ إِلَى قَوْلِهِ لَأَعْنَتَكُمْ }","trj":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] berkata; telah menceritakan kepada kami [Muhammad bin Ash Shalt] berkata; telah menceritakan kepada kami [Abu Kudainah] dari ['Atha] -yaitu Ibnu As Saib- dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Tatkala turun ayat: '(Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat) ' (Qs. Al Israa': 34), serta '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ibnu Abbas berkata, \"Maka orang-orang menjauhi harta anak yatim dan makanannya, sehingga hal tersebut terasa berat atas orang-orang muslim. Maka mereka mengadukan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, kemudian Allah menurunkan ayat: '(Dan mereka bertanya kepadamu tentang anak yatim, katakalah: \"Mengurus urusan mereka secara patut adalah baik, dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu; dan Allah mengetahui siapa yang membuat kerusakan dari yang mengadakan perbaikan. Dan jikalau Allah menghendaki, niscaya Dia dapat mendatangkan kesulitan kepadamu) ' (Qs. Al Baqarah: 220)."},{"p":"Tirmidzi","n":2909,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ وَمَا جَعَلْنَا الرُّؤْيَا الَّتِي أَرَيْنَاكَ إِلَّا فِتْنَةً لِلنَّاسِ }قَالَ هِيَ رُؤْيَا عَيْنٍ أُرِيَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ إِلَى بَيْتِ الْمَقْدِسِ قَالَ{ وَالشَّجَرَةَ الْمَلْعُونَةَ فِي الْقُرْآنِ }هِيَ شَجَرَةُ الزَّقُّومِقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Amru bin Dinar] dari [Ikrimah] dari [Ibnu Abbas] berkenaan dengan firman: \"Dan Kami tidak menjadikan mimpi yang telah Kami perlihatkan kepadamu, melainkan sebagai ujian bagi manusia\" (QS. Al-Isra'; 60), itulah mimpi nyata yang diperlihatkan kepada nabi Shallallahu 'alaihi wa Salam saat diisra`kan ke Baitul Maqdis, \"Dan (begitu pula) pohon kayu yang terkutuk dalam Al Qur`an.\" (Al Israa`: 60) maksudnya adalah pohon Zaqqum.\" Abu Isa mengatakan bahwa hadits ini hasan shahih."}]};
